var surah016 = {
  number: 16,
  nameArabic: "an-Nahl",
  nameEnglish: "An-Nahl",
  meaning: "The Bee",
  totalAyahs: 128,
  ayahs: [
    { number: 1, arabic: "أَتَىٰٓ أَمْرُ ٱللَّهِ فَلَا تَسْتَعْجِلُوهُ ۚ سُبْحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ", transliteration: "Ata amru Allahi fala tastaAAjiloohu subhanahu wataAAala AAamma yushrikoona", transliterationB: "Ataaa amrullaahi falaa tasta'jilooh; Subhaanahoo wa Ta'aalaa 'ammaa yushrikoon", english: "(Inevitable) cometh (to pass) the Command of Allah: seek ye not then to hasten it: Glory to Him, and far is He above having the partners they ascribe unto Him", romanUrdu: "Aagaya Allah ka faisla, ab iske liye jaldi na machao, paak hai woh aur baala-tar hai us shirk se jo yeh log kar rahey hain" },
    { number: 2, arabic: "يُنَزِّلُ ٱلْمَلَٰٓئِكَةَ بِٱلرُّوحِ مِنْ أَمْرِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦٓ أَنْ أَنذِرُوٓا۟ أَنَّهُۥ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱتَّقُونِ", transliteration: "Yunazzilu almalaikata bialrroohi min amrihi AAala man yashao min AAibadihi an anthiroo annahu la ilaha illa ana faittaqooni", transliterationB: "Yunazzilul malaaa 'ikata birroohi min amrihee 'alaa mai yashaaa'u min 'ibaadiheee an anzirooo annahoo laaa ilaaha illaaa ana fattaqoon", english: "He doth send down His angels with inspiration of His Command, to such of His servants as He pleaseth, (saying): \"Warn (Man) that there is no god but I: so do your duty unto Me", romanUrdu: "Woh is rooh ko apne jis banday par chahta hai apne hukum se malaika ke zariye nazil farma deta hai (is hidayat ke saath ke logon ko) “aagah kardo, mere siwa koi tumhara mabood nahin hai, lihaza tum mujhi se daro”" },
    { number: 3, arabic: "خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ تَعَٰلَىٰ عَمَّا يُشْرِكُونَ", transliteration: "Khalaqa alssamawati waalarda bialhaqqi taAAala AAamma yushrikoona", transliterationB: "Khalaqas samaawaati wal arda bilhaqq; Ta'aalaa 'ammaa yushrikoon", english: "He has created the heavens and the earth for just ends: Far is He above having the partners they ascribe to Him", romanUrdu: "Usne aasman o zameen ko barhaqq paida kiya hai, woh bahut baala o bartar hai us shirk se jo yeh log karte hain" },
    { number: 4, arabic: "خَلَقَ ٱلْإِنسَٰنَ مِن نُّطْفَةٍۢ فَإِذَا هُوَ خَصِيمٌۭ مُّبِينٌۭ", transliteration: "Khalaqa alinsana min nutfatin faitha huwa khaseemun mubeenun", transliterationB: "Khalaqal insaana min nutfatin fa izaa huwa khaseemum mubeen", english: "He has created man from a sperm-drop; and behold this same (man) becomes an open disputer", romanUrdu: "Usne Insaan ko ek zara si boondh se paida kiya aur dekhte dekhte sareehan woh ek jhagdalu hasti ban gaya" },
    { number: 5, arabic: "وَٱلْأَنْعَٰمَ خَلَقَهَا ۗ لَكُمْ فِيهَا دِفْءٌۭ وَمَنَٰفِعُ وَمِنْهَا تَأْكُلُونَ", transliteration: "WaalanAAama khalaqaha lakum feeha difon wamanafiAAu waminha takuloona", transliterationB: "Wal an 'amaa khalaqahaa; lakum feehaa dif'unw wa manaafi'u wa minhaa taakuloon", english: "And cattle He has created for you (men): from them ye derive warmth, and numerous benefits, and of their (meat) ye eat", romanUrdu: "Usne jaanwar paida kiye jinmein tumhare liye poshak (clothing) bhi hai aur khurak bhi, aur tarah tarah ke dusre faiyde bhi" },
    { number: 6, arabic: "وَلَكُمْ فِيهَا جَمَالٌ حِينَ تُرِيحُونَ وَحِينَ تَسْرَحُونَ", transliteration: "Walakum feeha jamalun heena tureehoona waheena tasrahoona", transliterationB: "Wa lakum feehaa jamaalun heena tureehoona wa heena tasrahoon", english: "And ye have a sense of pride and beauty in them as ye drive them home in the evening, and as ye lead them forth to pasture in the morning", romanUrdu: "Unmein tumhare liye jamal (pleasant look) hai jab ke subah tum unhein charne ke liye bhejte ho aur jabke shaam unhein wapas latey ho" },
    { number: 7, arabic: "وَتَحْمِلُ أَثْقَالَكُمْ إِلَىٰ بَلَدٍۢ لَّمْ تَكُونُوا۟ بَٰلِغِيهِ إِلَّا بِشِقِّ ٱلْأَنفُسِ ۚ إِنَّ رَبَّكُمْ لَرَءُوفٌۭ رَّحِيمٌۭ", transliteration: "Watahmilu athqalakum ila baladin lam takoonoo baligheehi illa bishiqqi alanfusi inna rabbakum laraoofun raheemun", transliterationB: "Wa tahmilu asqaalakum ilaa baladil lam takoonoo baaligheehi illaa bishiqqil anfus; inna Rabbakum la Ra'oofur Raheem", english: "And they carry your heavy loads to lands that ye could not (otherwise) reach except with souls distressed: for your Lord is indeed Most Kind, Most Merciful", romanUrdu: "Woh tumhare liye bojh dho (utha) kar aisey aisey muqaam tak le jatey hain jahan tum sakht jaanfishani (painful toil) ke bagair nahin pahunch sakte. Haqeeqat yeh hai ke tumhara Rubb bada hi shafeeq aur meharbaan hai" },
    { number: 8, arabic: "وَٱلْخَيْلَ وَٱلْبِغَالَ وَٱلْحَمِيرَ لِتَرْكَبُوهَا وَزِينَةًۭ ۚ وَيَخْلُقُ مَا لَا تَعْلَمُونَ", transliteration: "Waalkhayla waalbighala waalhameera litarkabooha wazeenatan wayakhluqu ma la taAAlamoona", transliterationB: "Walkhaila wal bighaala wal hameera litarkaboohaa wa zeenah; wa yakhluqu maa laa ta'lamoon", english: "And (He has created) horses, mules, and donkeys, for you to ride and use for show; and He has created (other) things of which ye have no knowledge", romanUrdu: "Usne ghodey (horses) aur khacchar (mule) aur gadhey paida kiya taa-ke tum unpar sawar ho aur woh tumhari zindagi ki raunak baney. Woh aur bhaut si cheezein (tumhare faiyde ke liye) paida karta hai jinka tumhein ilm tak nahin hai" },
    { number: 9, arabic: "وَعَلَى ٱللَّهِ قَصْدُ ٱلسَّبِيلِ وَمِنْهَا جَآئِرٌۭ ۚ وَلَوْ شَآءَ لَهَدَىٰكُمْ أَجْمَعِينَ", transliteration: "WaAAala Allahi qasdu alssabeeli waminha jairun walaw shaa lahadakum ajmaAAeena", transliterationB: "Wa 'alal laahi qasdus sabeeli wa minhaa jaaa'ir; wa law shaaa'a lahadaakum ajma'een", english: "And unto Allah leads straight the Way, but there are ways that turn aside: if Allah had willed, He could have guided all of you", romanUrdu: "Aur Allah hi ke zimme hai seedha raasta batana jabke raaste tedhey bhi maujood hain. Agar woh chahta to tum sabko hidayat de deta" },
    { number: 10, arabic: "هُوَ ٱلَّذِىٓ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ ۖ لَّكُم مِّنْهُ شَرَابٌۭ وَمِنْهُ شَجَرٌۭ فِيهِ تُسِيمُونَ", transliteration: "Huwa allathee anzala mina alssamai maan lakum minhu sharabun waminhu shajarun feehi tuseemoona", transliterationB: "Huwal lazeee anzala minas samaaa'i maaa'al lakum minhu sharaabunw wa minhu shajarun feehi tuseemoon", english: "It is He who sends down rain from the sky: from it ye drink, and out of it (grows) the vegetation on which ye feed your cattle", romanUrdu: "Wahi hai jisne aasman se tumhare liye pani barsaya jissey tum khud bhi sairaab hotey ho aur tumahre jaanwaron ke liye bhi chara paida hota hai" },
    { number: 11, arabic: "يُنۢبِتُ لَكُم بِهِ ٱلزَّرْعَ وَٱلزَّيْتُونَ وَٱلنَّخِيلَ وَٱلْأَعْنَٰبَ وَمِن كُلِّ ٱلثَّمَرَٰتِ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَتَفَكَّرُونَ", transliteration: "Yunbitu lakum bihi alzzarAAa waalzzaytoona waalnnakheela waalaAAnaba wamin kulli alththamarati inna fee thalika laayatan liqawmin yatafakkaroona", transliterationB: "Yumbitu lakum bihiz zar'a wazzaitoona wanna kheela wal-a'naaba wa min kullis samaraat, inna fee zaalika la Aayatal liqawminy yatafakkaroon", english: "With it He produces for you corn, olives, date-palms, grapes and every kind of fruit: verily in this is a sign for those who give thought", romanUrdu: "Woh is pani ke zariye se khetiyan ugata hai aur zaitun aur khajoor aur angoor aur tarah tarah ke dusre phal paida karta hai. Is mein ek badi nishani hai un logon ke liye jo gaur-o-fikr karte hain" },
    { number: 12, arabic: "وَسَخَّرَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ وَٱلشَّمْسَ وَٱلْقَمَرَ ۖ وَٱلنُّجُومُ مُسَخَّرَٰتٌۢ بِأَمْرِهِۦٓ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَعْقِلُونَ", transliteration: "Wasakhkhara lakumu allayla waalnnahara waalshshamsa waalqamara waalnnujoomu musakhkharatun biamrihi inna fee thalika laayatin liqawmin yaAAqiloona", transliterationB: "Wa sakkhkhara lakumul laila wannahaara wash shamsa walqamara wannujoomu musakhkharaatum bi amrih; inna fee zaalika la Aayaatil liqawminy ya'qiloon", english: "He has made subject to you the Night and the Day; the sun and the moon; and the stars are in subjection by His Command: verily in this are Signs for men who are wise", romanUrdu: "Usne tumhari bhalayi ke liye raat aur din ko aur Suraj aur Chand ko musakkhar kar rakkha hai, aur sab taare (stars) bhi usi ke hukum se musakkhar hain. Ismein bahut si nihsaniyan hain un logon ke liye jo aqal se kaam letey hain" },
    { number: 13, arabic: "وَمَا ذَرَأَ لَكُمْ فِى ٱلْأَرْضِ مُخْتَلِفًا أَلْوَٰنُهُۥٓ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَذَّكَّرُونَ", transliteration: "Wama tharaa lakum fee alardi mukhtalifan alwanuhu inna fee thalika laayatan liqawmin yaththakkaroona", transliterationB: "Wa maa zara a lakum fil ardi mukhtalifan alwaanuh; inna fee zaalika la Aayatal liqawminy yazakkaroon", english: "And the things on this earth which He has multiplied in varying colours (and qualities): verily in this is a sign for men who celebrate the praises of Allah (in gratitude)", romanUrdu: "Aur yeh jo bahut si rang bi rang ki cheezein usne tumhare liye zameen mein se paida kar rakkhi hai, in mein bhi zaroor nishani hai un logon ke liye jo sabaq haasil karne waley hain" },
    { number: 14, arabic: "وَهُوَ ٱلَّذِى سَخَّرَ ٱلْبَحْرَ لِتَأْكُلُوا۟ مِنْهُ لَحْمًۭا طَرِيًّۭا وَتَسْتَخْرِجُوا۟ مِنْهُ حِلْيَةًۭ تَلْبَسُونَهَا وَتَرَى ٱلْفُلْكَ مَوَاخِرَ فِيهِ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Wahuwa allathee sakhkhara albahra litakuloo minhu lahman tariyyan watastakhrijoo minhu hilyatan talbasoonaha watara alfulka mawakhira feehi walitabtaghoo min fadlihi walaAAallakum tashkuroona", transliterationB: "Wa Huwal lazee sakhkharal bahra litaakuloo minhu lahman tariyyanw wa tastakhrijoo minhu hilyatan talbasoonahaa wa taral fulka mawaakhira feehi wa litabtaghoo min fadlihee wa la'allakum tashkuroon", english: "It is He Who has made the sea subject, that ye may eat thereof flesh that is fresh and tender, and that ye may extract therefrom ornaments to wear; and thou seest the ships therein that plough the waves, that ye may seek (thus) of the bounty of Allah and that ye may be grateful", romanUrdu: "Wahi hai jisne tumhare liye samandar ko musakkhar kar rakkha hai taa-ke tum ussey tarr-o-taaza gosht lekar khao aur ussey zeenat (adornment) ki woh cheezein nikalo jinhein tum pehna karte ho. Tum dekhte ho ke kashti samandar ka seena cheerti hui chalti hai, yeh sab kuch is liye hai ke tum apne Rubb ka fazal talash karo aur uske shukar-guzar bano" },
    { number: 15, arabic: "وَأَلْقَىٰ فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِكُمْ وَأَنْهَٰرًۭا وَسُبُلًۭا لَّعَلَّكُمْ تَهْتَدُونَ", transliteration: "Waalqa fee alardi rawasiya an tameeda bikum waanharan wasubulan laAAallakum tahtadoona", transliterationB: "Wa alqaa fil ardi rawaasiya an tameeda bikum wa anhaaranw wa sublulal la 'allakum tahtadoon", english: "And He has set up on the earth mountains standing firm, lest it should shake with you; and rivers and roads; that ye may guide yourselves", romanUrdu: "Usne zameen mein pahadon ki mekhein gaadh di taa-ke zameen tumko lekar dhulak na jaye, usne dariya jari kiya aur qudrati raaste banaye taa-ke tum hidayat pao" },
    { number: 16, arabic: "وَعَلَٰمَٰتٍۢ ۚ وَبِٱلنَّجْمِ هُمْ يَهْتَدُونَ", transliteration: "WaAAalamatin wabialnnajmi hum yahtadoona", transliterationB: "Wa 'alaamaat; wa bin najmi hum yahtadoon", english: "And marks and sign-posts; and by the stars (men) guide themselves", romanUrdu: "Usne zameen mein raasta batane wali alamatein rakh di , aur taaron (stars) se bhi log hidayat paate hain" },
    { number: 17, arabic: "أَفَمَن يَخْلُقُ كَمَن لَّا يَخْلُقُ ۗ أَفَلَا تَذَكَّرُونَ", transliteration: "Afaman yakhluqu kaman la yakhluqu afala tathakkaroona", transliterationB: "Afamany yakhluqu kamallaa yakhluq; afalaa tazak karoon", english: "Is then He Who creates like one that creates not? Will ye not receive admonition", romanUrdu: "Phir kya woh jo paida karta hai aur woh jo kuch bhi paida nahin karte, dono yaksan hain? Kya tum hosh mein nahin aatey" },
    { number: 18, arabic: "وَإِن تَعُدُّوا۟ نِعْمَةَ ٱللَّهِ لَا تُحْصُوهَآ ۗ إِنَّ ٱللَّهَ لَغَفُورٌۭ رَّحِيمٌۭ", transliteration: "Wain taAAuddoo niAAmata Allahi la tuhsooha inna Allaha laghafoorun raheemun", transliterationB: "Wa in ta'uddoo ni'matal laahi laa tuhsoohaa; innal laaha la Ghafoorur Raheem", english: "If ye would count up the favours of Allah, never would ye be able to number them: for Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Agar tum Allah ki niyamaton ko ginna chaho to gin nahin sakte, haqeeqat yeh hai ke woh bada hi darguzar karne wala aur raheem hai" },
    { number: 19, arabic: "وَٱللَّهُ يَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَ", transliteration: "WaAllahu yaAAlamu ma tusirroona wama tuAAlinoona", transliterationB: "Wallaahu ya'lamu maa tusirroona wa maa tu'linoon", english: "And Allah doth know what ye conceal, and what ye reveal", romanUrdu: "Halanke woh tumhare khule se bhi waqif hai aur chupey se bhi" },
    { number: 20, arabic: "وَٱلَّذِينَ يَدْعُونَ مِن دُونِ ٱللَّهِ لَا يَخْلُقُونَ شَيْـًۭٔا وَهُمْ يُخْلَقُونَ", transliteration: "Waallatheena yadAAoona min dooni Allahi la yakhluqoona shayan wahum yukhlaqoona", transliterationB: "Wallazeena yad'oona min doonil laahi laa yakhluqoona shai'anw wa hum yukhlaqoon", english: "Those whom they invoke besides Allah create nothing and are themselves created", romanUrdu: "Aur woh dusri hastiyan jinhein Allah ko chodh kar log pukarte hain, woh kisi cheez ke bhi khaliq nahin hain balke khud makhlooq hain" },
    { number: 21, arabic: "أَمْوَٰتٌ غَيْرُ أَحْيَآءٍۢ ۖ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَ", transliteration: "Amwatun ghayru ahyain wama yashAAuroona ayyana yubAAathoona", transliterationB: "Amwaatun ghairu ahyaaa'inw wa maa yash'uroona aiyaana yub'asoon", english: "(They are things) dead, lifeless: nor do they know when they will be raised up", romanUrdu: "Murda hain na ke zinda aur unko kuch maloom nahin hai ke unhein kab (dobara zinda karke) uthaya jayega" },
    { number: 22, arabic: "إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۚ فَٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ قُلُوبُهُم مُّنكِرَةٌۭ وَهُم مُّسْتَكْبِرُونَ", transliteration: "Ilahukum ilahun wahidun faallatheena la yuminoona bialakhirati quloobuhum munkiratun wahum mustakbiroona", transliterationB: "Illahukum Ilaahunw Waahid; fallazeena laa yu'minoona bil Aakhirati quloobuhum munkiratunw wa hum mustakbiroon", english: "Your Allah is one Allah: as to those who believe not in the Hereafter, their hearts refuse to know, and they are arrogant", romanUrdu: "Tumhara khuda bas ek hi khuda hai magar jo log aakhirat ko nahin maante unke dilon mein inkar baskar reh gaya hai aur woh ghamand mein padh gaye hain" },
    { number: 23, arabic: "لَا جَرَمَ أَنَّ ٱللَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْتَكْبِرِينَ", transliteration: "La jarama anna Allaha yaAAlamu ma yusirroona wama yuAAlinoona innahu la yuhibbu almustakbireena", transliterationB: "Laa jarama annal laaha ya'lamu maa yusirrona wa ma yu'linoon; innahoo laa yuhibbul mustakbireen", english: "Undoubtedly Allah doth know what they conceal, and what they reveal: verily He loveth not the arrogant", romanUrdu: "Allah yaqeenan inke sab karoot jaanta hai chupe huye bhi aur khule huye bhi. Woh un logon ko hargiz pasand nahin karta jo guroor e nafs (puffed up with pride) mein mubtala hon" },
    { number: 24, arabic: "وَإِذَا قِيلَ لَهُم مَّاذَآ أَنزَلَ رَبُّكُمْ ۙ قَالُوٓا۟ أَسَٰطِيرُ ٱلْأَوَّلِينَ", transliteration: "Waitha qeela lahum matha anzala rabbukum qaloo asateeru alawwaleena", transliterationB: "Wa izaa qeela lahum maazaaa anzala Rabbukum qaaloo asaateerul awwaleen", english: "When it is said to them, \"What is it that your Lord has revealed?\" they say, \"Tales of the ancients", romanUrdu: "Aur jab koi unse poochta hai ke tumhare Rubb ne yeh kya cheez nazil ki hai to kehte hain, “aji woh to agle waqton ki farsuda kahaniyan (ancient tales) hain”" },
    { number: 25, arabic: "لِيَحْمِلُوٓا۟ أَوْزَارَهُمْ كَامِلَةًۭ يَوْمَ ٱلْقِيَٰمَةِ ۙ وَمِنْ أَوْزَارِ ٱلَّذِينَ يُضِلُّونَهُم بِغَيْرِ عِلْمٍ ۗ أَلَا سَآءَ مَا يَزِرُونَ", transliteration: "Liyahmiloo awzarahum kamilatan yawma alqiyamati wamin awzari allatheena yudilloonahum bighayri AAilmin ala saa ma yaziroona", transliterationB: "Liyahmilooo awzaarahum kaamilatany Yawmal Qiyaamati wa min awzaaril lazeena yudilloonahum bighairi 'ilm; alaa saaa'a maa yaziroon", english: "Let them bear, on the Day of Judgment, their own burdens in full, and also (something) of the burdens of those without knowledge, whom they misled. Alas, how grievous the burdens they will bear", romanUrdu: "Yeh baatein woh isliye karte hain ke qayamat ke roz apne bojh bhi poore uthayein, aur saath saath kuch un logon ke bojh bhi sametein jinhien yeh baar binaye jihalat (in their ignorance) gumraah kar rahey hain. Dekho! Kaisi sakht zimmedari hai jo yeh apne sar ley rahey hain" },
    { number: 26, arabic: "قَدْ مَكَرَ ٱلَّذِينَ مِن قَبْلِهِمْ فَأَتَى ٱللَّهُ بُنْيَٰنَهُم مِّنَ ٱلْقَوَاعِدِ فَخَرَّ عَلَيْهِمُ ٱلسَّقْفُ مِن فَوْقِهِمْ وَأَتَىٰهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ", transliteration: "Qad makara allatheena min qablihim faata Allahu bunyanahum mina alqawaAAidi fakharra AAalayhimu alssaqfu min fawqihim waatahumu alAAathabu min haythu la yashAAuroona", transliterationB: "Qad makaral lazeena min qablihim fa atal laahu bunyaa nahum minal qawaa'idi fakharra 'alaihimus saqfu min fawqihim wa ataahumul 'azaabu min haisu laa yash'uroon", english: "Those before them did also plot (against Allah's Way): but Allah took their structures from their foundations, and the roof fell down on them from above; and the Wrath seized them from directions they did not perceive", romanUrdu: "Inse pehle bhi bahut se log (haqq ko nicha dikhane ke liye) aisi hi makkariyan kar chuke hain, to dekhlo ke Allah ne unke makr ki imarat jadd (root) se ukhad phenki aur uski chatt upar se unke sar par aa rahi (roof fell down upon their heads from above them) aur aisey rukh se unpar azaab aaya jidhar se uske aane ka unko gumaan tak na tha" },
    { number: 27, arabic: "ثُمَّ يَوْمَ ٱلْقِيَٰمَةِ يُخْزِيهِمْ وَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تُشَٰٓقُّونَ فِيهِمْ ۚ قَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ إِنَّ ٱلْخِزْىَ ٱلْيَوْمَ وَٱلسُّوٓءَ عَلَى ٱلْكَٰفِرِينَ", transliteration: "Thumma yawma alqiyamati yukhzeehim wayaqoolu ayna shurakaiya allatheena kuntum tushaqqoona feehim qala allatheena ootoo alAAilma inna alkhizya alyawma waalssooa AAala alkafireena", transliterationB: "Summa Yawmal Qiyaamati yukhzeehim wa yaqoolu aina shurakaaa'iyal lazeena kuntum tushaaaqqoona feehim; qaalal lazeena ootul 'ilma innal khizyal Yawma wassooo'a 'alal kaafireen", english: "Then, on the Day of Judgment, He will cover them with shame, and say: \"Where are My 'partners' concerning whom ye used to dispute (with the godly)?\" Those endued with knowledge will say: \"This Day, indeed, are the Unbelievers covered with shame and misery", romanUrdu: "Phir qayamat ke roz Allah unhein zaleel o khwar karega aur unse kahega “ batao, ab kahan hain mere woh shareek jinke liye tum (ehle haqq se) jhagde kiya karte thay?” Jin logon ko duniya mein ilm haasil tha woh kahenge “ aaj ruswayi aur badbakhti hai kafiron ke liye”" },
    { number: 28, arabic: "ٱلَّذِينَ تَتَوَفَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ ظَالِمِىٓ أَنفُسِهِمْ ۖ فَأَلْقَوُا۟ ٱلسَّلَمَ مَا كُنَّا نَعْمَلُ مِن سُوٓءٍۭ ۚ بَلَىٰٓ إِنَّ ٱللَّهَ عَلِيمٌۢ بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Allatheena tatawaffahumu almalaikatu thalimee anfusihim faalqawoo alssalama ma kunna naAAmalu min sooin bala inna Allaha AAaleemun bima kuntum taAAmaloona", transliterationB: "Allazeena tatawaf faahu mul malaaa'ikatu zaalimeee anfusihim fa alqawus salama maa kunnaa na'malu min sooo'; balaaa innal laaha 'aleemum bimaa kuntum ta'maloon", english: "(Namely) those whose lives the angels take in a state of wrong-doing to their own souls.\" Then would they offer submission (with the pretence), \"We did no evil (knowingly).\" (The angels will reply), \"Nay, but verily Allah knoweth all that ye did", romanUrdu: "Haan, unhi kaafiron ke liye jo apne nafs par zulm karte huey jab malaika ke haathon giraftar hotay hain to (sarkashi chodh kar) fawran dagein daal dete (surrender) hain aur kehte hain “hum to koi kasoor nahin kar rahey thay”. Malaika jawab dete hain “kar kaise nahin rahey thay! Allah tumhare kartooton se khoob waqif hai" },
    { number: 29, arabic: "فَٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَٰلِدِينَ فِيهَا ۖ فَلَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ", transliteration: "Faodkhuloo abwaba jahannama khalideena feeha falabisa mathwa almutakabbireena", transliterationB: "Fadkhulooo abwaaba jahannama khaalideena feeha falabi'sa maswal mutakab bireen", english: "So enter the gates of Hell, to dwell therein. Thus evil indeed is the abode of the arrogant", romanUrdu: "Ab jao, jahannum ke darwazon mein ghuss jao, wahin tumko hamesha rehna hai”. Pas haqeeqat yeh hai ke bada hi bura thikana hai mutakabbiron (haughty ones) ke liye" },
    { number: 30, arabic: "۞ وَقِيلَ لِلَّذِينَ ٱتَّقَوْا۟ مَاذَآ أَنزَلَ رَبُّكُمْ ۚ قَالُوا۟ خَيْرًۭا ۗ لِّلَّذِينَ أَحْسَنُوا۟ فِى هَٰذِهِ ٱلدُّنْيَا حَسَنَةٌۭ ۚ وَلَدَارُ ٱلْءَاخِرَةِ خَيْرٌۭ ۚ وَلَنِعْمَ دَارُ ٱلْمُتَّقِينَ", transliteration: "Waqeela lillatheena ittaqaw matha anzala rabbukum qaloo khayran lillatheena ahsanoo fee hathihi alddunya hasanatun waladaru alakhirati khayrun walaniAAma daru almuttaqeena", transliterationB: "Wa qeela lillazeenat taqaw maazaaa anzala Rabbukum; qaaloo khairaa; lillazeena absanoo fee haazihid dunyaa hasanah; wa la Daarul Aakhirati khair; wa lani'ma daarul muttaqeen", english: "To the righteous (when) it is said, \"What is it that your Lord has revealed?\" they say, \"All that is good.\" To those who do good, there is good in this world, and the Home of the Hereafter is even better and excellent indeed is the Home of the righteous", romanUrdu: "Dusri taraf jab khuda tars logon se pucha jata hai ke yeh kya cheez hai jo tumhare Rubb ki taraf se nazil hui hai, to woh jawab dete hain ke “behtareen cheez utari hai”. Is tarah ke neikukar logon ke liye is duniya mein bhi bhalayi hai aur aakhirat ka ghar to zaroor hi unke haqq mein behtar hai. Bada accha ghar hai muttaqiyon (Allah se darne walon) ka" },
    { number: 31, arabic: "جَنَّٰتُ عَدْنٍۢ يَدْخُلُونَهَا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۖ لَهُمْ فِيهَا مَا يَشَآءُونَ ۚ كَذَٰلِكَ يَجْزِى ٱللَّهُ ٱلْمُتَّقِينَ", transliteration: "Jannatu AAadnin yadkhuloonaha tajree min tahtiha alanharu lahum feeha ma yashaoona kathalika yajzee Allahu almuttaqeena", transliterationB: "Jannaatu 'Adniny yadkhuloonahaa tajree min tahtihal anhaaru lahum feehaa maa yashaaa'oon; kazaalika yajzil laahul muttaqeen", english: "Gardens of Eternity which they will enter: beneath them flow (pleasant) rivers: they will have therein all that they wish: thus doth Allah reward the righteous", romanUrdu: "Daimi qayam (permanent residence) ki jannatein, jin mein woh dakhil hongey, nichey nehrein beh rahi hongi, aur sab kuch wahan ain unki khwahish ke mutabiq hoga. Yeh jaza deta hai Allah muttaqiyon (pious) ko" },
    { number: 32, arabic: "ٱلَّذِينَ تَتَوَفَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ طَيِّبِينَ ۙ يَقُولُونَ سَلَٰمٌ عَلَيْكُمُ ٱدْخُلُوا۟ ٱلْجَنَّةَ بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Allatheena tatawaffahumu almalaikatu tayyibeena yaqooloona salamun AAalaykumu odkhuloo aljannata bima kuntum taAAmaloona", transliterationB: "Allazeena tatawaf faahumul malaaa'ikatu taiyibeena yaqooloona salaamun 'alai kumud khulul Jannata bimaa kuntum ta'maloon", english: "(Namely) those whose lives the angels take in a state of purity, saying (to them), \"Peace be on you; enter ye the Garden, because of (the good) which ye did (in the world)", romanUrdu: "Un muttaqiyon ko jinki roohein pakeezgi ki haalat mein jab malaika qabz karte hain to kehte hain “salaam ho tumpar, jao jannat mein apne aamaal ke badle”" },
    { number: 33, arabic: "هَلْ يَنظُرُونَ إِلَّآ أَن تَأْتِيَهُمُ ٱلْمَلَٰٓئِكَةُ أَوْ يَأْتِىَ أَمْرُ رَبِّكَ ۚ كَذَٰلِكَ فَعَلَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "Hal yanthuroona illa an tatiyahumu almalaikatu aw yatiya amru rabbika kathalika faAAala allatheena min qablihim wama thalamahumu Allahu walakin kanoo anfusahum yathlimoona", transliterationB: "Hal yanzuroona illaaa an taatiyahumul malaaa'ikatu aw yaatiya amru Rabbik; kazaalika fa'alal lazeena min qablihim; wa maa zalamahumul laahu wa laakin kaanoo anfusahum yazlimoon", english: "Do the (ungodly) wait until the angels come to them, or there comes the Command of thy Lord (for their doom)? So did those who went before them. But Allah wronged them not: nay, they wronged their own souls", romanUrdu: "(Aey Muhammad), ab jo yeh log intezar kar rahey hain to iske siwa ab aur kya baki reh gaya hai ke Malaika hi aa pahunchein, ya tere Rubb ka faisla saadir ho jaye? Is tarah ki dhitayi inse pehle bahut se log kar chuke hain, phir jo kuch unke saath hua woh unpar Allah ka zulm na tha balke unka apna zulm tha jo unhon ne khud apne upar kiya" },
    { number: 34, arabic: "فَأَصَابَهُمْ سَيِّـَٔاتُ مَا عَمِلُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Faasabahum sayyiatu ma AAamiloo wahaqa bihim ma kanoo bihi yastahzioona", transliterationB: "Fa asaabahum saiyi aatu maa 'amiloo wa haaqa bihim maa kaano bihee yastahzi'oon", english: "But the evil results of their deeds overtook them, and that very (Wrath) at which they had scoffed hemmed them in", romanUrdu: "Unke kartooton ki kharabiyan aakhir unki daamangeer ho gayi aur wahi cheez unpar musallat hokar rahi jiska woh mazaaq udaya karte thay" },
    { number: 35, arabic: "وَقَالَ ٱلَّذِينَ أَشْرَكُوا۟ لَوْ شَآءَ ٱللَّهُ مَا عَبَدْنَا مِن دُونِهِۦ مِن شَىْءٍۢ نَّحْنُ وَلَآ ءَابَآؤُنَا وَلَا حَرَّمْنَا مِن دُونِهِۦ مِن شَىْءٍۢ ۚ كَذَٰلِكَ فَعَلَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ فَهَلْ عَلَى ٱلرُّسُلِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ", transliteration: "Waqala allatheena ashrakoo law shaa Allahu ma AAabadna min doonihi min shayin nahnu wala abaona wala harramna min doonihi min shayin kathalika faAAala allatheena min qablihim fahal AAala alrrusuli illa albalaghu almubeenu", transliterationB: "Wa qaalal lazeena ashrakoo law shaaa'al laahu ma 'abadnaa min doonihee min shai'in nahnu wa laaa aabaaa'unaa wa laa harramnaa min doonihee min shai'; kazaalika fa'alal lazeena min qablihim fahal 'alar Rusuli illal balaaghul mubeen", english: "The worshippers of false gods say: \"If Allah had so willed, we should not have worshipped aught but Him - neither we nor our fathers,- nor should we have prescribed prohibitions other than His.\" So did those who went before them. But what is the mission of messengers but to preach the Clear Message", romanUrdu: "Yeh mushrikeen kehte hain “agar Allah chahta to na hum aur na hamare baap dada uske siwa kisi aur ki ibadat karte aur na uske hukum ke bagair kisi cheez ko haraam thehrate”. Aisey hi bahane insey pehle ke log bhi banate rahey hain to kya Rasoolon par saaf saaf baat pahuncha dene ke siwa aur bhi koi zimmedari hai" },
    { number: 36, arabic: "وَلَقَدْ بَعَثْنَا فِى كُلِّ أُمَّةٍۢ رَّسُولًا أَنِ ٱعْبُدُوا۟ ٱللَّهَ وَٱجْتَنِبُوا۟ ٱلطَّٰغُوتَ ۖ فَمِنْهُم مَّنْ هَدَى ٱللَّهُ وَمِنْهُم مَّنْ حَقَّتْ عَلَيْهِ ٱلضَّلَٰلَةُ ۚ فَسِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُكَذِّبِينَ", transliteration: "Walaqad baAAathna fee kulli ommatin rasoolan ani oAAbudoo Allaha waijtaniboo alttaghoota faminhum man hada Allahu waminhum man haqqat AAalayhi alddalalatu faseeroo fee alardi faonthuroo kayfa kana AAaqibatu almukaththibeena", transliterationB: "Wa laqad ba'asnaa fee kulli ummatir Rasoolan ani'budul laaha wajtanibut Taaghoota faminhum man hadal laahu wa minhum man haqqat 'alaihid dalaalah; faseeroo fil ardi fanzuroo kaifa kaana 'aaqibatul mukazzibeen", english: "For We assuredly sent amongst every People a messenger, (with the Command), \"Serve Allah, and eschew Evil\": of the People were some whom Allah guided, and some on whom error became inevitably (established). So travel through the earth, and see what was the end of those who denied (the Truth)", romanUrdu: "Humne har ummat mein ek Rasool bhej diya, aur uske zariye se sabko khabardar kardiya ke “Allah ki bandagi karo aur taghut ki bandagi se bacho”. Iske baad in mein se kisi ko Allah ne hidayat bakshi aur kisi par zalalat musallat ho gayi. Phir zara zameen mein chal phir kar dekhlo ke jhutlane walon ka kya anjaam ho chuka hai" },
    { number: 37, arabic: "إِن تَحْرِصْ عَلَىٰ هُدَىٰهُمْ فَإِنَّ ٱللَّهَ لَا يَهْدِى مَن يُضِلُّ ۖ وَمَا لَهُم مِّن نَّٰصِرِينَ", transliteration: "In tahris AAala hudahum fainna Allaha la yahdee man yudillu wama lahum min nasireena", transliterationB: "In tahris 'alaa hudaahum fa innal laaha laa yahdee mai yudillu wa maa lahum min naasireen", english: "If thou art anxious for their guidance, yet Allah guideth not such as He leaves to stray, and there is none to help them", romanUrdu: "(Aey Muhammad), tum chahe inki hidayat ke liye kitne hi harees (desirous) ho, magar Allah jisko bhatka deta hai phir usey hidayat nahin diya karta aur is tarah ke logon ki madad koi nahin kar sakta" },
    { number: 38, arabic: "وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَٰنِهِمْ ۙ لَا يَبْعَثُ ٱللَّهُ مَن يَمُوتُ ۚ بَلَىٰ وَعْدًا عَلَيْهِ حَقًّۭا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Waaqsamoo biAllahi jahda aymanihim la yabAAathu Allahu man yamootu bala waAAdan AAalayhi haqqan walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Wa aqsamoo billaahi jahda aimaanihim laa yab'asul laahu mai yamoot; balaa wa'dan 'alaihi haqqanw wa laakinna aksaran naasi laa ya'lamoon", english: "They swear their strongest oaths by Allah, that Allah will not raise up those who die: Nay, but it is a promise (binding) on Him in truth: but most among mankind realise it not", romanUrdu: "Yeh log Allah ke naam se kadi kadi kasmein kha kar kehte hain ke “Allah kisi marne waley ko phir se zinda karke na uthayega”. Uthayega kyun nahin, yeh to ek wada hai jisey poora karna usne apne upar wajib karliye hai, magar aksar log jantey nahin hain" },
    { number: 39, arabic: "لِيُبَيِّنَ لَهُمُ ٱلَّذِى يَخْتَلِفُونَ فِيهِ وَلِيَعْلَمَ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّهُمْ كَانُوا۟ كَٰذِبِينَ", transliteration: "Liyubayyina lahumu allathee yakhtalifoona feehi waliyaAAlama allatheena kafaroo annahum kanoo kathibeena", transliterationB: "Liyubaiyina lahumul lazee yakhtalifoona feehi wa liya'lamal lazeena kafarooo annahum kaanoo kaazibeen", english: "(They must be raised up), in order that He may manifest to them the truth of that wherein they differ, and that the rejecters of Truth may realise that they had indeed (surrendered to) Falsehood", romanUrdu: "Aur aisa hona isliye zaroori hai ke Allah inke samne us haqeeqat ko khol de jiske barey mein yeh ikhtilaf kar rahey hain aur munkireen e haqq ko maloom ho jaye ke woh jhoote thay" },
    { number: 40, arabic: "إِنَّمَا قَوْلُنَا لِشَىْءٍ إِذَآ أَرَدْنَٰهُ أَن نَّقُولَ لَهُۥ كُن فَيَكُونُ", transliteration: "Innama qawluna lishayin itha aradnahu an naqoola lahu kun fayakoonu", transliterationB: "Innamaa qawlunaa lisha y'in izaa aradnaahu an naqoola lahoo kun fa yakoon", english: "For to anything which We have willed, We but say the word, \"Be\", and it is", romanUrdu: "Raha uska imakan (possibility) to] humein kisi cheez ko wajood mein laney ke liye issey zyada kuch nahin karna hota ke usey hukum dein “ho ja” aur bas woh ho jaati hai" },
    { number: 41, arabic: "وَٱلَّذِينَ هَاجَرُوا۟ فِى ٱللَّهِ مِنۢ بَعْدِ مَا ظُلِمُوا۟ لَنُبَوِّئَنَّهُمْ فِى ٱلدُّنْيَا حَسَنَةًۭ ۖ وَلَأَجْرُ ٱلْءَاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ", transliteration: "Waallatheena hajaroo fee Allahi min baAAdi ma thulimoo lanubawwiannahum fee alddunya hasanatan walaajru alakhirati akbaru law kanoo yaAAlamoona", transliterationB: "Wallazeena haajaroo fil laahi mim ba'di maa zulimoo lanubawwi' annahum fiddunyaa hasanatanw wa la ajrul Aakhirati akbar; law kaanoo ya'lamoon", english: "To those who leave their homes in the cause of Allah, after suffering oppression,- We will assuredly give a goodly home in this world; but truly the reward of the Hereafter will be greater. If they only realised (this)", romanUrdu: "Jo log zulm sehne ke baad Allah ki khatir hijrat kar gaye hain unko hum duniya hi mein accha thikana denge aur aakhirat ka ajar to bahut bada hai, kaash jaan lein woh mazloom" },
    { number: 42, arabic: "ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", transliteration: "Allatheena sabaroo waAAala rabbihim yatawakkaloona", transliterationB: "Allazeena sabaroo wa 'alaa Rabbihim yatawak kaloon", english: "(They are) those who persevere in patience, and put their trust on their Lord", romanUrdu: "Jinhon ne sabr kiya hai aur jo apne Rubb ke bharosey par kaam kar rahey hain (ke kaisa accha anjaam unka muntazir hai)" },
    { number: 43, arabic: "وَمَآ أَرْسَلْنَا مِن قَبْلِكَ إِلَّا رِجَالًۭا نُّوحِىٓ إِلَيْهِمْ ۚ فَسْـَٔلُوٓا۟ أَهْلَ ٱلذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ", transliteration: "Wama arsalna min qablika illa rijalan noohee ilayhim faisaloo ahla alththikri in kuntum la taAAlamoona", transliterationB: "Wa maaa arsalnaa min qablika illaa rijaalan nooheee ilaihim; fas'alooo ahlaz zikri in kuntum laa ta'lamoon", english: "And before thee also the messengers We sent were but men, to whom We granted inspiration: if ye realise this not, ask of those who possess the Message", romanUrdu: "(Aey Muhammad), humne tumse pehle bhi jab kabhi Rasool bheje hain aadmi hi bheje hain jinki taraf hum apne paigamaat wahee kiya karte thay. Ehle zikr se puch lo agar tumlog khud nahin jaante" },
    { number: 44, arabic: "بِٱلْبَيِّنَٰتِ وَٱلزُّبُرِ ۗ وَأَنزَلْنَآ إِلَيْكَ ٱلذِّكْرَ لِتُبَيِّنَ لِلنَّاسِ مَا نُزِّلَ إِلَيْهِمْ وَلَعَلَّهُمْ يَتَفَكَّرُونَ", transliteration: "Bialbayyinati waalzzuburi waanzalna ilayka alththikra litubayyina lilnnasi ma nuzzila ilayhim walaAAallahum yatafakkaroona", transliterationB: "Bilbaiyinaati waz Zubur; wa anzalnaaa ilaikaz Zikra litubaiyina linnaasi maa nuzzila ilaihim wa la'allahum yatafakkaroon", english: "(We sent them) with Clear Signs and Books of dark prophecies; and We have sent down unto thee (also) the Message; that thou mayest explain clearly to men what is sent for them, and that they may give thought", romanUrdu: "Pichle Rasoolon ko bhi humne roshan nishaniyan aur kitabein de kar bheja tha, aur ab yeh zikr tumpar nazil kiya hai taa-ke tum logon ke saamne us taleem ki tashreeh o tawzeeh karte jao jo unke liye utari gayi hai, aur taa-ke log (khud bhi) gaur o fikr karein" },
    { number: 45, arabic: "أَفَأَمِنَ ٱلَّذِينَ مَكَرُوا۟ ٱلسَّيِّـَٔاتِ أَن يَخْسِفَ ٱللَّهُ بِهِمُ ٱلْأَرْضَ أَوْ يَأْتِيَهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ", transliteration: "Afaamina allatheena makaroo alssayyiati an yakhsifa Allahu bihimu alarda aw yatiyahumu alAAathabu min haythu la yashAAuroona", transliterationB: "Afa aminal lazeena makarus saiyi aati ai yakhsifal laahu bihimul arda aw yaaa tiyahumul 'azaabu min haisu laa yash'uroon", english: "Do then those who devise evil (plots) feel secure that Allah will not cause the earth to swallow them up, or that the Wrath will not seize them from directions they little perceive", romanUrdu: "Phir kya woh log jo ( dawat e paigambar ki mukhalifat mein) badhtar se badhtar chalein chal rahey hain is baat se bilkul hi be khauf ho gaye hain ke Allah unko zameen mein dhansa de, ya aisey goshey mein unpar azaab le aaye jidhar se uske aane ka unko weham o gumaan tak na ho" },
    { number: 46, arabic: "أَوْ يَأْخُذَهُمْ فِى تَقَلُّبِهِمْ فَمَا هُم بِمُعْجِزِينَ", transliteration: "Aw yakhuthahum fee taqallubihim fama hum bimuAAjizeena", transliterationB: "Aw yaakhuzahum fee taqallubihim famaa hum bi mu'jizeen", english: "Or that He may not call them to account in the midst of their goings to and fro, without a chance of their frustrating Him", romanUrdu: "Ya achanak chalte phirte inko pakad le , ya aisi halat mein inhein pakde jabke unhein khud aane wali museebat ka khatka laga hua ho aur woh ussey bachne ki fikr mein chaukanne hon" },
    { number: 47, arabic: "أَوْ يَأْخُذَهُمْ عَلَىٰ تَخَوُّفٍۢ فَإِنَّ رَبَّكُمْ لَرَءُوفٌۭ رَّحِيمٌ", transliteration: "Aw yakhuthahum AAala takhawwufin fainna rabbakum laraoofun raheemun", transliterationB: "Aw yaakhuzahum 'alaa takhawwuf; fa inna Rabbakum la Ra'oofur Raheem", english: "Or that He may not call them to account by a process of slow wastage - for thy Lord is indeed full of kindness and mercy", romanUrdu: "Woh jo kuch bhi karna chahe yeh log usko aajiz (frustrate) karne ki taaqat nahin rakhte, haqeeqat yeh hai ke tumhara Rubb bada hi narm-khu (very Lenient /shafaqat karne wala) aur raheem hai" },
    { number: 48, arabic: "أَوَلَمْ يَرَوْا۟ إِلَىٰ مَا خَلَقَ ٱللَّهُ مِن شَىْءٍۢ يَتَفَيَّؤُا۟ ظِلَٰلُهُۥ عَنِ ٱلْيَمِينِ وَٱلشَّمَآئِلِ سُجَّدًۭا لِّلَّهِ وَهُمْ دَٰخِرُونَ", transliteration: "Awa lam yaraw ila ma khalaqa Allahu min shayin yatafayyao thilaluhu AAani alyameeni waalshshamaili sujjadan lillahi wahum dakhiroona", transliterationB: "Awa lam yaraw ilaa maa khalaqal laahu min shai'iny-yatafaiya'u zilaaluhoo 'anil yameeni washshamaaa' ili sujjadal lillaahi wa hum daakhiroon", english: "Do they not look at Allah's creation, (even) among (inanimate) things,- How their (very) shadows turn round, from the right and the left, prostrating themselves to Allah, and that in the humblest manner", romanUrdu: "Aur kya yeh log Allah ki paida ki hui kisi cheez ko bhi nahin dekhte ke uska saaya kis tarah Allah ke huzoor sajda karte huey dayein aur bayein girta hai? Sab ke sab is tarah izhar e ijz (express their humility) kar rahey hain" },
    { number: 49, arabic: "وَلِلَّهِ يَسْجُدُ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ مِن دَآبَّةٍۢ وَٱلْمَلَٰٓئِكَةُ وَهُمْ لَا يَسْتَكْبِرُونَ", transliteration: "Walillahi yasjudu ma fee alssamawati wama fee alardi min dabbatin waalmalaikatu wahum la yastakbiroona", transliterationB: "Wa lillaahi yasjudu maa fis samaawaati wa maa fil ardi min daaabbatinw walma laaa'ikatu wa hum laa yastakbiroon", english: "And to Allah doth obeisance all that is in the heavens and on earth, whether moving (living) creatures or the angels: for none are arrogant (before their Lord)", romanUrdu: "Zameen aur aasmano mein jis qadar jaandaar makhlooqat hain aur jitne Malaika hain sab Allah ke aagey sar ba-sajood hain. Woh hargiz sarkashi nahin karte" },
    { number: 50, arabic: "يَخَافُونَ رَبَّهُم مِّن فَوْقِهِمْ وَيَفْعَلُونَ مَا يُؤْمَرُونَ ۩", transliteration: "Yakhafoona rabbahum min fawqihim wayafAAaloona ma yumaroona", transliterationB: "yakhaafoona Rabbahum min fawqihim wa yaf'aloona maa yu'maroon", english: "They all revere their Lord, high above them, and they do all that they are commanded", romanUrdu: "Apne Rubb se jo unke upar hai, darte hain aur jo kuch hukum diya jata hai usi ke mutabik kaam karte hain" },
    { number: 51, arabic: "۞ وَقَالَ ٱللَّهُ لَا تَتَّخِذُوٓا۟ إِلَٰهَيْنِ ٱثْنَيْنِ ۖ إِنَّمَا هُوَ إِلَٰهٌۭ وَٰحِدٌۭ ۖ فَإِيَّٰىَ فَٱرْهَبُونِ", transliteration: "Waqala Allahu la tattakhithoo ilahayni ithnayni innama huwa ilahun wahidun faiyyaya fairhabooni", transliterationB: "Wa qaalal laahu laa tatta khizooo ilaahainis naini innamaa Huwa Ilaahunw Waahid; fa iyyaaya farhaboon", english: "Allah has said: \"Take not (for worship) two gods: for He is just One Allah: then fear Me (and Me alone)", romanUrdu: "Allah ka farmaan hai ke “do khuda na bana lo, khuda to bas ek hi hai, lihaza tum mujhi se daro" },
    { number: 52, arabic: "وَلَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَلَهُ ٱلدِّينُ وَاصِبًا ۚ أَفَغَيْرَ ٱللَّهِ تَتَّقُونَ", transliteration: "Walahu ma fee alssamawati waalardi walahu alddeenu wasiban afaghayra Allahi tattaqoona", transliterationB: "Wa lahoo maa fis samaawaati wal ardi wa lahud deenu waasibaa; afaghairal laahi tattaqoon", english: "To Him belongs whatever is in the heavens and on earth, and to Him is duty due always: then will ye fear other than Allah", romanUrdu: "Usi ka hai woh sab kuch jo aasmano mein hai aur jo zameen mein hai, aur khaalisan usi ka deen (saari qayinaat mein) chal raha hai. Phir kya Allah ko chodh kar tum kisi aur se taqwa (darr) karoge" },
    { number: 53, arabic: "وَمَا بِكُم مِّن نِّعْمَةٍۢ فَمِنَ ٱللَّهِ ۖ ثُمَّ إِذَا مَسَّكُمُ ٱلضُّرُّ فَإِلَيْهِ تَجْـَٔرُونَ", transliteration: "Wama bikum min niAAmatin famina Allahi thumma itha massakumu alddurru failayhi tajaroona", transliterationB: "Wa maa bikum minni'matin faminal laahi summa izaa massakumud durru fa ilaihi taj'aroon", english: "And ye have no good thing but is from Allah: and moreover, when ye are touched by distress, unto Him ye cry with groans", romanUrdu: "Tumko jo niyamat bhi haasil hai Allah hi ki taraf se hai phir jab koi sakht waqt tumpar aata hai to tum log khud apni fariyadein lekar usi ki taraf daudte ho" },
    { number: 54, arabic: "ثُمَّ إِذَا كَشَفَ ٱلضُّرَّ عَنكُمْ إِذَا فَرِيقٌۭ مِّنكُم بِرَبِّهِمْ يُشْرِكُونَ", transliteration: "Thumma itha kashafa alddurra AAankum itha fareequn minkum birabbihim yushrikoona", transliterationB: "Summaa izaa kashafad durra 'ankum izaa fareequm minkum bi Rabbihim yushrikoon", english: "Yet, when He removes the distress from you, behold! some of you turn to other gods to join with their Lord", romanUrdu: "Magar jab Allah us waqt ko taal deta hai to yakayak tum mein se ek giroh apne Rubb ke saath dusron ko (is meharbani ke shukriye mein) shareek karne lagta hai" },
    { number: 55, arabic: "لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَٰهُمْ ۚ فَتَمَتَّعُوا۟ ۖ فَسَوْفَ تَعْلَمُونَ", transliteration: "Liyakfuroo bima ataynahum fatamattaAAoo fasawfa taAAlamoona", transliterationB: "Liyakfuroo bimaa aatainaahum; fatamatta'oo, faswfa ta'lamoon", english: "(As if) to show their ingratitude for the favours we have bestowed on them! then enjoy (your brief day): but soon will ye know (your folly)", romanUrdu: "Taa-ke Allah ke ehsan ki nashukri karey, Accha mazey karlo, anqareeb tumhein maloom ho jayega" },
    { number: 56, arabic: "وَيَجْعَلُونَ لِمَا لَا يَعْلَمُونَ نَصِيبًۭا مِّمَّا رَزَقْنَٰهُمْ ۗ تَٱللَّهِ لَتُسْـَٔلُنَّ عَمَّا كُنتُمْ تَفْتَرُونَ", transliteration: "WayajAAaloona lima la yaAAlamoona naseeban mimma razaqnahum taAllahi latusalunna AAamma kuntum taftaroona", transliterationB: "Wa yaj'aloona limaa laa ya'lamoona naseebam mimmaa razaqnnaahum; tallaahi latus'alunaa 'ammaa kuntum taftaroon", english: "And they (even) assign, to things they do not know, a portion out of that which We have bestowed for their sustenance! By Allah, ye shall certainly be called to account for your false inventions", romanUrdu: "Yeh log jinki haqeeqat se waqif nahin hain unke hissey hamare diye huye rizq mein se muqarrar karte hain. Khuda ki kasam, zaroor tumse pucha jayega ke yeh jhoot tumne kaise ghadh liye thay" },
    { number: 57, arabic: "وَيَجْعَلُونَ لِلَّهِ ٱلْبَنَٰتِ سُبْحَٰنَهُۥ ۙ وَلَهُم مَّا يَشْتَهُونَ", transliteration: "WayajAAaloona lillahi albanati subhanahu walahum ma yashtahoona", transliterationB: "Wa yaj'aloona lillaahil banaati Subhaanahoo wa lahum maa yashtahoon", english: "And they assign daughters for Allah! - Glory be to Him! - and for themselves (sons,- the issue) they desire", romanUrdu: "Yeh khuda ke liye betiyan tajweez karte hain, SubhanAllah! Aur inke liye woh jo yeh khud chahein" },
    { number: 58, arabic: "وَإِذَا بُشِّرَ أَحَدُهُم بِٱلْأُنثَىٰ ظَلَّ وَجْهُهُۥ مُسْوَدًّۭا وَهُوَ كَظِيمٌۭ", transliteration: "Waitha bushshira ahaduhum bialontha thalla wajhuhu muswaddan wahuwa katheemun", transliterationB: "Wa izaa bushshira ahaduhum bil unsaa zalla wajhuhoo muswaddanw wa huwa kazeem", english: "When news is brought to one of them, of (the birth of) a female (child), his face darkens, and he is filled with inward grief", romanUrdu: "Jab in mein se kisi ko beti ke paida honay ki khush-khabri di jati hai to uske chehre par kaloons (grows dark) chaa jati hai aur woh bas khoon ka sa ghoont pee kar reh jata hai" },
    { number: 59, arabic: "يَتَوَٰرَىٰ مِنَ ٱلْقَوْمِ مِن سُوٓءِ مَا بُشِّرَ بِهِۦٓ ۚ أَيُمْسِكُهُۥ عَلَىٰ هُونٍ أَمْ يَدُسُّهُۥ فِى ٱلتُّرَابِ ۗ أَلَا سَآءَ مَا يَحْكُمُونَ", transliteration: "Yatawara mina alqawmi min sooi ma bushshira bihi ayumsikuhu AAala hoonin am yadussuhu fee altturabi ala saa ma yahkumoona", transliterationB: "yatawaaraa minal qawmimin sooo'i maa bushshira bih; a-yumsikuhoo 'alaa hoonin am yadussuhoo fit turaab; alaa saaa'a maa yahkumoon", english: "With shame does he hide himself from his people, because of the bad news he has had! Shall he retain it on (sufferance and) contempt, or bury it in the dust? Ah! what an evil (choice) they decide on", romanUrdu: "Logon se chupta phirta hai ke is buri khabar ke baad kya kisi ko mooh dikhaye. Sochta hai ke zillat ke saath beti ko liye rahey ya mitti mein daba de? Dekho kaise bure hukum hain jo yeh khuda ke barey mein lagate hain" },
    { number: 60, arabic: "لِلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ مَثَلُ ٱلسَّوْءِ ۖ وَلِلَّهِ ٱلْمَثَلُ ٱلْأَعْلَىٰ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Lillatheena la yuminoona bialakhirati mathalu alssawi walillahi almathalu alaAAla wahuwa alAAazeezu alhakeemu", transliterationB: "Lillazeena laa yu'minoona bil Aakhirati masalus saw'i wa lillaahil masalul a'laa; wa Huwal 'Azeezul Hakeem", english: "To those who believe not in the Hereafter, applies the similitude of evil: to Allah applies the highest similitude: for He is the Exalted in Power, full of Wisdom", romanUrdu: "Buri siffat se muttasaf (be ascribed) kiya janey ke layak to woh log hain jo aakhirat ka yaqeen nahin rakhte. Raha Allah, to uske liye sab se bartar siffat hain, wahi to sab par gaalib aur hikmat mein kamil hai" },
    { number: 61, arabic: "وَلَوْ يُؤَاخِذُ ٱللَّهُ ٱلنَّاسَ بِظُلْمِهِم مَّا تَرَكَ عَلَيْهَا مِن دَآبَّةٍۢ وَلَٰكِن يُؤَخِّرُهُمْ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى ۖ فَإِذَا جَآءَ أَجَلُهُمْ لَا يَسْتَـْٔخِرُونَ سَاعَةًۭ ۖ وَلَا يَسْتَقْدِمُونَ", transliteration: "Walaw yuakhithu Allahu alnnasa bithulmihim ma taraka AAalayha min dabbatin walakin yuakhkhiruhum ila ajalin musamman faitha jaa ajaluhum la yastakhiroona saAAatan wala yastaqdimoona", transliterationB: "Wa law yu'aakhizul laahun naasa bizulminhim maa taraka 'alaihaa min daaabbatinw wa laakiny yu'akhkhiruhum ilaaa ajalim musamman fa izaa jaaa'a ajaluhum laa yastaakhiroona saa'atanw wa laa yastaqdimoon", english: "If Allah were to punish men for their wrong-doing, He would not leave, on the (earth), a single living creature: but He gives them respite for a stated Term: When their Term expires, they would not be able to delay (the punishment) for a single hour, just as they would not be able to anticipate it (for a single hour)", romanUrdu: "Agar kahin Allah logon ko unki zyadati par fauran hi pakad liya karta to rooh e zameen par kisi mutanaffis ko na chodhta. Lekin woh sab ko ek waqt e muqarrar tak mohalat deta hai. Phir jab woh waqt aa jata hai to ussey koi ek ghadi bhar bhi aagey peechey nahin ho sakta" },
    { number: 62, arabic: "وَيَجْعَلُونَ لِلَّهِ مَا يَكْرَهُونَ وَتَصِفُ أَلْسِنَتُهُمُ ٱلْكَذِبَ أَنَّ لَهُمُ ٱلْحُسْنَىٰ ۖ لَا جَرَمَ أَنَّ لَهُمُ ٱلنَّارَ وَأَنَّهُم مُّفْرَطُونَ", transliteration: "WayajAAaloona lillahi ma yakrahoona watasifu alsinatuhumu alkathiba anna lahumu alhusna la jarama anna lahumu alnnara waannahum mufratoona", transliterationB: "Wa yaj'aloona lillaahi maa yakrahoona wa tasifu alsinatuhumul kaziba anna lahumul husnaa laa jarama anna lahumun Naara wa annahum mufratoon", english: "They attribute to Allah what they hate (for themselves), and their tongues assert the falsehood that all good things are for themselves: without doubt for them is the Fire, and they will be the first to be hastened on into it", romanUrdu: "Aaj yeh log woh cheezein Allah ke liye tajweez kar rahey hain jo khud apne liye inhein napasand hain, aur jhoot kehti hain inki zubaanein ke inke liye bhala hi bhala hai. Inke liye to ek hi cheez hai, aur woh hai dozakh ki aag, zaroor yeh sab se pehle us mein pahunchaye jayenge" },
    { number: 63, arabic: "تَٱللَّهِ لَقَدْ أَرْسَلْنَآ إِلَىٰٓ أُمَمٍۢ مِّن قَبْلِكَ فَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَهُوَ وَلِيُّهُمُ ٱلْيَوْمَ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "TaAllahi laqad arsalna ila omamin min qablika fazayyana lahumu alshshaytanu aAAmalahum fahuwa waliyyuhumu alyawma walahum AAathabun aleemun", transliterationB: "Tallaahi laqad arsalnaaa ilaaa umamim min qablika fazayyana lahumush Shaitaanu a'maalahum fahuwa waliyyuhumul yawma wa lahum 'azaabun aleem", english: "By Allah, We (also) sent (Our messengers) to Peoples before thee; but Satan made, (to the wicked), their own acts seem alluring: He is also their patron today, but they shall have a most grievous penalty", romanUrdu: "Khuda ki kasam, (aey Muhammad) tumse pehle bhi bahut si qaumon mein hum Rasool bhej chuke hain (aur pehle bhi yahi hota raha hai ke) shaytan ne unke burey kartoot unhein khushnuma bana kar dikhaye (aur Rasoolon ki baat unhon ne maan kar na di). Wahi shaytan aaj in logon ka bhi sarparast bana hua hai aur yeh dardnaak saza ke mustahiq ban rahey hain" },
    { number: 64, arabic: "وَمَآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَٰبَ إِلَّا لِتُبَيِّنَ لَهُمُ ٱلَّذِى ٱخْتَلَفُوا۟ فِيهِ ۙ وَهُدًۭى وَرَحْمَةًۭ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Wama anzalna AAalayka alkitaba illa litubayyina lahumu allathee ikhtalafoo feehi wahudan warahmatan liqawmin yuminoona", transliterationB: "Wa maaa anzalnaa 'alaikal Kitaaba illaa litubaiyina lahumul lazikh talafoo feehi wa hudanw wa rahmatal liqawminy yu'minoon", english: "And We sent down the Book to thee for the express purpose, that thou shouldst make clear to them those things in which they differ, and that it should be a guide and a mercy to those who believe", romanUrdu: "Humne yeh kitaab tumpar is liye nazil ki hai ke tum un ikhtilafaat(differences) ki haqeeqat inpar khol do jin mein yeh padey huey hain. Yeh kitab rehnumayi aur rehmat bankar utri hai un logon ke liye jo isey maan lein" },
    { number: 65, arabic: "وَٱللَّهُ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَسْمَعُونَ", transliteration: "WaAllahu anzala mina alssamai maan faahya bihi alarda baAAda mawtiha inna fee thalika laayatan liqawmin yasmaAAoona", transliterationB: "Wallaahu anzala minas samaaa'i maaa'an fa ahyaa bihil arda ba'da mawtihaa; inna fee zaalika la aayatal liqaw miny yasma'oon", english: "And Allah sends down rain from the skies, and gives therewith life to the earth after its death: verily in this is a Sign for those who listen", romanUrdu: "(Tum har barsaat mein dekhte ho ke) Allah ne aasman se pani barsaya aur yakayak murda padi hui zameen mein uski badaulat jaan daal di. Yaqeenan is mein ek nishani hain sunne walon ke liye" },
    { number: 66, arabic: "وَإِنَّ لَكُمْ فِى ٱلْأَنْعَٰمِ لَعِبْرَةًۭ ۖ نُّسْقِيكُم مِّمَّا فِى بُطُونِهِۦ مِنۢ بَيْنِ فَرْثٍۢ وَدَمٍۢ لَّبَنًا خَالِصًۭا سَآئِغًۭا لِّلشَّٰرِبِينَ", transliteration: "Wainna lakum fee alanAAami laAAibratan nusqeekum mimma fee butoonihi min bayni farthin wadamin labanan khalisan saighan lilshsharibeena", transliterationB: "Wa inna lakum fil an'aami la'ibrah; nusqeekum mimmmaa fee butoonihee mim baini farsinw wa damil labanann khaalisan saaa'ighallish shaaribeen", english: "And verily in cattle (too) will ye find an instructive sign. From what is within their bodies between excretions and blood, We produce, for your drink, milk, pure and agreeable to those who drink it", romanUrdu: "Aur tumhare liye maweshiyon mein bhi ek sabaq maujood hai unke pait (stomach) se gobar aur khoon ke darmiyan hum ek cheez tumhein peelate hain, yaani khaalis doodh, jo peene walon ke liye nihayat khushgawar hai" },
    { number: 67, arabic: "وَمِن ثَمَرَٰتِ ٱلنَّخِيلِ وَٱلْأَعْنَٰبِ تَتَّخِذُونَ مِنْهُ سَكَرًۭا وَرِزْقًا حَسَنًا ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَعْقِلُونَ", transliteration: "Wamin thamarati alnnakheeli waalaAAnabi tattakhithoona minhu sakaran warizqan hasanan inna fee thalika laayatan liqawmin yaAAqiloona", transliterationB: "Wa min samaraatin nakheeli wal a'nnaabi tattakhizoona minhu sakaranw wa rizqann hasanaa; inna fee zaalika la Aayatal liqawminy ya'qiloon", english: "And from the fruit of the date-palm and the vine, ye get out wholesome drink and food: behold, in this also is a sign for those who are wise", romanUrdu: "(Isi tarah) khajoor ke darakhton aur angoor ki beilon se bhi hum ek cheez tumhein pilatay hain jisey tum nasha-awar bhi bana letey ho aur paak rizq bhi. Yaqeenan is mein ek nishani hai aqal se kaam lene walon ke liye" },
    { number: 68, arabic: "وَأَوْحَىٰ رَبُّكَ إِلَى ٱلنَّحْلِ أَنِ ٱتَّخِذِى مِنَ ٱلْجِبَالِ بُيُوتًۭا وَمِنَ ٱلشَّجَرِ وَمِمَّا يَعْرِشُونَ", transliteration: "Waawha rabbuka ila alnnahli ani ittakhithee mina aljibali buyootan wamina alshshajari wamimma yaAArishoona", transliterationB: "Wa awhaa Rabbuka ilannnabli anit takhizee minal jabaali buyootanw wa minash shajari wa mimmaa ya'rishoon", english: "And thy Lord taught the Bee to build its cells in hills, on trees, and in (men's) habitations", romanUrdu: "Aur dekho, tumhare Rubb ne shahed (honey) ki makkhi par yeh baat wahee kardi ke pahadon mein, aur darakhton mein, aur tattiyon par chadhayi hui bailon mein (mountains, trees and in the creepers over trellises) apne chattey bana (Build your hive)" },
    { number: 69, arabic: "ثُمَّ كُلِى مِن كُلِّ ٱلثَّمَرَٰتِ فَٱسْلُكِى سُبُلَ رَبِّكِ ذُلُلًۭا ۚ يَخْرُجُ مِنۢ بُطُونِهَا شَرَابٌۭ مُّخْتَلِفٌ أَلْوَٰنُهُۥ فِيهِ شِفَآءٌۭ لِّلنَّاسِ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَتَفَكَّرُونَ", transliteration: "Thumma kulee min kulli alththamarati faoslukee subula rabbiki thululan yakhruju min butooniha sharabun mukhtalifun alwanuhu feehi shifaon lilnnasi inna fee thalika laayatan liqawmin yatafakkaroona", transliterationB: "Summma kulee min kullis samaraati faslukee subula Rabbiki zululaa; yakhruju mim butoonihaa sharaabum mukh talifun alwaanuhoo feehi shifaaa'ul linnaas, innna fee zaalika la Aayatal liqawminy yatafakkaroon", english: "Then to eat of all the produce (of the earth), and find with skill the spacious paths of its Lord: there issues from within their bodies a drink of varying colours, wherein is healing for men: verily in this is a Sign for those who give thought", romanUrdu: "Aur har tarah ke phoolon ka rass choos aur apne Rubb ki humwar ki hui raahon par chalti reh. Is makkhi ke andar se rang bi rang ka ek sharbat nikalta hai jismein shifa hai logon ke liye. Yaqeenan is mein bhi ek nishani hai un logon ke liye jo gaur o fikr karte hain" },
    { number: 70, arabic: "وَٱللَّهُ خَلَقَكُمْ ثُمَّ يَتَوَفَّىٰكُمْ ۚ وَمِنكُم مَّن يُرَدُّ إِلَىٰٓ أَرْذَلِ ٱلْعُمُرِ لِكَىْ لَا يَعْلَمَ بَعْدَ عِلْمٍۢ شَيْـًٔا ۚ إِنَّ ٱللَّهَ عَلِيمٌۭ قَدِيرٌۭ", transliteration: "WaAllahu khalaqakum thumma yatawaffakum waminkum man yuraddu ila arthali alAAumuri likay la yaAAlama baAAda AAilmin shayan inna Allaha AAaleemun qadeerun", transliterationB: "Wallaahu khalaqakum suma tatawaffaakum; wa minkum many-yuradu ilaaa arzalil 'umuri likai laa ya'lama ba'da 'ilmin shai'aa; innal laaha 'Aleemun Qadeer", english: "It is Allah who creates you and takes your souls at death; and of you there are some who are sent back to a feeble age, so that they know nothing after having known (much): for Allah is All-Knowing, All-Powerful", romanUrdu: "Aur dekho, Allah ne tumko paida kiya, phir woh tumko maut deta hai aur tum mein se koi badhtareen umar ko pahucha diya jata hai taa-ke sab kuch jaanne ke baad phir kuch na janey. Haqq yeh hai ke Allah hi ilm mein bhi kamil hai aur qudrat mein bhi" },
    { number: 71, arabic: "وَٱللَّهُ فَضَّلَ بَعْضَكُمْ عَلَىٰ بَعْضٍۢ فِى ٱلرِّزْقِ ۚ فَمَا ٱلَّذِينَ فُضِّلُوا۟ بِرَآدِّى رِزْقِهِمْ عَلَىٰ مَا مَلَكَتْ أَيْمَٰنُهُمْ فَهُمْ فِيهِ سَوَآءٌ ۚ أَفَبِنِعْمَةِ ٱللَّهِ يَجْحَدُونَ", transliteration: "WaAllahu faddala baAAdakum AAala baAAdin fee alrrizqi fama allatheena fuddiloo biraddee rizqihim AAala ma malakat aymanuhum fahum feehi sawaon afabiniAAmati Allahi yajhadoona", transliterationB: "Wallaahu faddala ba'dakum 'alaa ba'din fir rizq; famal lazeena fuddiloo biraaaddee rizqihim 'alaa maa malakat aimaanuhum fahum feehi sawaaa'; afabini'matil laahi yajhadoon", english: "Allah has bestowed His gifts of sustenance more freely on some of you than on others: those more favoured are not going to throw back their gifts to those whom their right hands possess, so as to be equal in that respect. Will they then deny the favours of Allah", romanUrdu: "Aur dekho, Allah ne tum mein se baaz ko baaz par rizq mein fazilat ata ki hai, phir jin logon ko yeh fazeelat di gayi hai woh aisey nahin hain ke apna rizq apne ghulaamo ki taraf pher diya karte hon taa-ke dono is rizq mein barabar ke hissedaar ban jayein. To kya Allah hi ka ehsan maanne se in logon ko inkar hai" },
    { number: 72, arabic: "وَٱللَّهُ جَعَلَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًۭا وَجَعَلَ لَكُم مِّنْ أَزْوَٰجِكُم بَنِينَ وَحَفَدَةًۭ وَرَزَقَكُم مِّنَ ٱلطَّيِّبَٰتِ ۚ أَفَبِٱلْبَٰطِلِ يُؤْمِنُونَ وَبِنِعْمَتِ ٱللَّهِ هُمْ يَكْفُرُونَ", transliteration: "WaAllahu jaAAala lakum min anfusikum azwajan wajaAAala lakum min azwajikum baneena wahafadatan warazaqakum mina alttayyibati afabialbatili yuminoona wabiniAAmati Allahi hum yakfuroona", transliterationB: "Wallaahu ja'ala lakum min anfusikum azwaajanw wa ja'ala lakum min azwaajikum baneena wa hafadatanw wa razaqakum minat yaiyibaat; afabil baatili yu'minoona wa bini'matil laahi hum yakkfuroon", english: "And Allah has made for you mates (and companions) of your own nature, and made for you, out of them, sons and daughters and grandchildren, and provided for you sustenance of the best: will they then believe in vain things, and be ungrateful for Allah's favours", romanUrdu: "Aur woh Allah hi hai jisne tumhare liye tumhari hum jins biwiyan banayi aur usi ne un biwiyon se tumhein bete potey (sons and grandsons) ata kiye aur acchi acchi cheezein tumhein khane ko di. Phir kya yeh log (yeh sab kuch dekhte aur jaante huey bhi) baatil ko maante hain, aur Allah ke ehsan ka inkar karte hain" },
    { number: 73, arabic: "وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَمْلِكُ لَهُمْ رِزْقًۭا مِّنَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ شَيْـًۭٔا وَلَا يَسْتَطِيعُونَ", transliteration: "WayaAAbudoona min dooni Allahi ma la yamliku lahum rizqan mina alssamawati waalardi shayan wala yastateeAAoona", transliterationB: "Wa ya'budoona min doonil laahi maa laa yamliku lahum rizqam minas samaawaati wal ardi shai'anw wa laa yastatee'oon", english: "And worship others than Allah,- such as have no power of providing them, for sustenance, with anything in heavens or earth, and cannot possibly have such power", romanUrdu: "Aur Allah ko chodh kar unko poojhte hain jinke haath mein na aasmano se inhein kuch bhi rizq dena hai na zameen se aur na yeh kaam woh kar hi sakte hain" },
    { number: 74, arabic: "فَلَا تَضْرِبُوا۟ لِلَّهِ ٱلْأَمْثَالَ ۚ إِنَّ ٱللَّهَ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", transliteration: "Fala tadriboo lillahi alamthala inna Allaha yaAAlamu waantum la taAAlamoona", transliterationB: "Falaa tadriboo lillaahil amsaal; innal laaha ya'lamu wa antum laa ta'lamoon", english: "Invent not similitudes for Allah: for Allah knoweth, and ye know not", romanUrdu: "Pas Allah ke liye misalein na ghado, Allah jaanta hai, tum nahin jaante" },
    { number: 75, arabic: "۞ ضَرَبَ ٱللَّهُ مَثَلًا عَبْدًۭا مَّمْلُوكًۭا لَّا يَقْدِرُ عَلَىٰ شَىْءٍۢ وَمَن رَّزَقْنَٰهُ مِنَّا رِزْقًا حَسَنًۭا فَهُوَ يُنفِقُ مِنْهُ سِرًّۭا وَجَهْرًا ۖ هَلْ يَسْتَوُۥنَ ۚ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ", transliteration: "Daraba Allahu mathalan AAabdan mamlookan la yaqdiru AAala shayin waman razaqnahu minna rizqan hasanan fahuwa yunfiqu minhu sirran wajahran hal yastawoona alhamdu lillahi bal aktharuhum la yaAAlamoona", transliterationB: "Darabal laahu masalan 'abdam mammlookal laa yaqdiru 'alaa shai'inw wa marrazaqnaahu mminnaa rizqan hasanan fahuwa yunfiqu minhu sirranw wa jahra; hal yasta-woon; alhamdu lillaah; bal aksaruhum laa ya'lamoon", english: "Allah sets forth the Parable (of two men: one) a slave under the dominion of another; He has no power of any sort; and (the other) a man on whom We have bestowed goodly favours from Ourselves, and he spends thereof (freely), privately and publicly: are the two equal? (By no means;) praise be to Allah. But most of them understand not", romanUrdu: "Allah ek misal deta hai ek to hai gulaam, jo dusre ka mamluq (slave) hai aur khud koi ikhtiyar nahin rakhta. Doosra shaks aisa hai jisey humne apni taraf se accha rizq ata kiya hai aur woh is mein se khule aur chupe khoob kharch karta hai. Batao kya yeh dono barabar hain? Alhamdulillah, magar aksar log (is seedhi baat ko) nahin jaante" },
    { number: 76, arabic: "وَضَرَبَ ٱللَّهُ مَثَلًۭا رَّجُلَيْنِ أَحَدُهُمَآ أَبْكَمُ لَا يَقْدِرُ عَلَىٰ شَىْءٍۢ وَهُوَ كَلٌّ عَلَىٰ مَوْلَىٰهُ أَيْنَمَا يُوَجِّههُّ لَا يَأْتِ بِخَيْرٍ ۖ هَلْ يَسْتَوِى هُوَ وَمَن يَأْمُرُ بِٱلْعَدْلِ ۙ وَهُوَ عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Wadaraba Allahu mathalan rajulayni ahaduhuma abkamu la yaqdiru AAala shayin wahuwa kallun AAala mawlahu aynama yuwajjihhu la yati bikhayrin hal yastawee huwa waman yamuru bialAAadli wahuwa AAala siratin mustaqeemin", transliterationB: "Wa darabal laahu masalar rajulaini ahaduhumaaa abkamu laa yaqdiru 'alaa shai'inw wa huwa kallun 'alaa mawlaahu ainamaa yuwajjihhu laa yaati bikhairin hal yastawee huwa wa many-yaamuru bil'adli wa huwa 'alaa Siraatim MMustaqeem", english: "Allah sets forth (another) Parable of two men: one of them dumb, with no power of any sort; a wearisome burden is he to his master; whichever way be directs him, he brings no good: is such a man equal with one who commands Justice, and is on a Straight Way", romanUrdu: "Allah ek aur misal deta hai, do aadmi hain ek gunga behra hai, koi kaam nahin kar sakta, apne aaqa par bojh bana hua hai, jidhar bhi woh usey bheje koi bhala kaam ussey ban na aaye, dusra shaks aisa hai ke insaaf ka hukum deta hai aur khud raah e raast par qayam hai, batao kya yeh dono yaksan hain" },
    { number: 77, arabic: "وَلِلَّهِ غَيْبُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَآ أَمْرُ ٱلسَّاعَةِ إِلَّا كَلَمْحِ ٱلْبَصَرِ أَوْ هُوَ أَقْرَبُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Walillahi ghaybu alssamawati waalardi wama amru alssaAAati illa kalamhi albasari aw huwa aqrabu inna Allaha AAala kulli shayin qadeerun", transliterationB: "Wa lillaahi ghaibus samaawaati wal ard; wa maaa amrus Saa'ati illaa kalamhil basari aw huwa aqrab; innal laaha 'alaaa kulli shai'in Qadeer", english: "To Allah belongeth the Mystery of the heavens and the earth. And the Decision of the Hour (of Judgment) is as the twingkling of an eye, or even quicker: for Allah hath power over all things", romanUrdu: "Aur zameen o aasman ke posheeda haqaiq ka ilm to Allah hi ko hai aur qayamant ke barpa honay ka maamla kuch dair na lega magar bas itni ke jismein aadmi ki palakh jhapak jaye, balke isse bhi kuch kam, haqeeqat yeh hai ke Allah sab kuch kar sakta hai" },
    { number: 78, arabic: "وَٱللَّهُ أَخْرَجَكُم مِّنۢ بُطُونِ أُمَّهَٰتِكُمْ لَا تَعْلَمُونَ شَيْـًۭٔا وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۙ لَعَلَّكُمْ تَشْكُرُونَ", transliteration: "WaAllahu akhrajakum min butooni ommahatikum la taAAlamoona shayan wajaAAala lakumu alssamAAa waalabsara waalafidata laAAallakum tashkuroona", transliterationB: "Wallaahu akhrajakum mim butooni ummahaatikum laa ta'lamoona shai'anw wa ja'ala lakumus sam'a wal absaara wal af'idata la'allakum tashkuroon", english: "It is He Who brought you forth from the wombs of your mothers when ye knew nothing; and He gave you hearing and sight and intelligence and affections: that ye may give thanks (to Allah)", romanUrdu: "Allah ne tumko tumhari maaon ke paiton se nikala is halat mein ke tum kuch na jaante thay, usne tumhein kaan diye , aankhein di , aur sochne waley dil diya, is liye ke tum shukar-guzaar bano" },
    { number: 79, arabic: "أَلَمْ يَرَوْا۟ إِلَى ٱلطَّيْرِ مُسَخَّرَٰتٍۢ فِى جَوِّ ٱلسَّمَآءِ مَا يُمْسِكُهُنَّ إِلَّا ٱللَّهُ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Alam yaraw ila alttayri musakhkharatin fee jawwi alssamai ma yumsikuhunna illa Allahu inna fee thalika laayatin liqawmin yuminoona", transliterationB: "Alam yaraw ilat tairi musakhkharaatin fee jawwis samaaa'i maa yumsikuhunna illal laah; inna fee zaalika la Aayaatil liqawminy yu'minoon", english: "Do they not look at the birds, held poised in the midst of (the air and) the sky? Nothing holds them up but (the power of) Allah. Verily in this are signs for those who believe", romanUrdu: "Kya in logon ne kabhi parindon ko nahin dekha ke fiza e aasmani mein kis tarah musakkhar hain? Allah ke siwa kisne inko thaam rakkha hai? Is mein bahut nishaniyan hain un logon ke liye jo iman latey hain" },
    { number: 80, arabic: "وَٱللَّهُ جَعَلَ لَكُم مِّنۢ بُيُوتِكُمْ سَكَنًۭا وَجَعَلَ لَكُم مِّن جُلُودِ ٱلْأَنْعَٰمِ بُيُوتًۭا تَسْتَخِفُّونَهَا يَوْمَ ظَعْنِكُمْ وَيَوْمَ إِقَامَتِكُمْ ۙ وَمِنْ أَصْوَافِهَا وَأَوْبَارِهَا وَأَشْعَارِهَآ أَثَٰثًۭا وَمَتَٰعًا إِلَىٰ حِينٍۢ", transliteration: "WaAllahu jaAAala lakum min buyootikum sakanan wajaAAala lakum min juloodi alanAAami buyootan tastakhiffoonaha yawma thaAAnikum wayawma iqamatikum wamin aswafiha waawbariha waashAAariha athathan wamataAAan ila heenin", transliterationB: "Wallaahu ja'ala lakum min juloodil an'aami buyootan tastakhif foonahaa yawma za'nikum wa yawma iqaamatikum wa min aswaafihaa wa awbaarihaa wa ash'aarihaaa asaasanw wa mataa'an ilaa been", english: "It is Allah Who made your habitations homes of rest and quiet for you; and made for you, out of the skins of animals, (tents for) dwellings, which ye find so light (and handy) when ye travel and when ye stop (in your travels); and out of their wool, and their soft fibres (between wool and hair), and their hair, rich stuff and articles of convenience (to serve you) for a time", romanUrdu: "Allah ne tumhare liye tumhare gharon ko jaaye sukoon banaya, usne jaanwaron ki khaalon (skins) se tumhare liye aisey makan paida kiye jinhein tum safar aur qayaam, dono haalaton mein halka patey ho. Usne jaanwaron ke souf aur oun aur baalon se (soft fur and wool and hair) pehanne aur baratne (use) ki bahut si cheezein paida kardi jo zindagi ki muddat e muqarrara tak tumhare kaam aati hain" },
    { number: 81, arabic: "وَٱللَّهُ جَعَلَ لَكُم مِّمَّا خَلَقَ ظِلَٰلًۭا وَجَعَلَ لَكُم مِّنَ ٱلْجِبَالِ أَكْنَٰنًۭا وَجَعَلَ لَكُمْ سَرَٰبِيلَ تَقِيكُمُ ٱلْحَرَّ وَسَرَٰبِيلَ تَقِيكُم بَأْسَكُمْ ۚ كَذَٰلِكَ يُتِمُّ نِعْمَتَهُۥ عَلَيْكُمْ لَعَلَّكُمْ تُسْلِمُونَ", transliteration: "WaAllahu jaAAala lakum mimma khalaqa thilalan wajaAAala lakum mina aljibali aknanan wajaAAala lakum sarabeela taqeekumu alharra wasarabeela taqeekum basakum kathalika yutimmu niAAmatahu AAalaykum laAAallakum tuslimoona", transliterationB: "Wallaahu ja'ala lakum mimmaa khalaqa zilaalanw wa ja'ala lakum minal jibaali aknaananw wa ja'ala lakum saraabeela taqeekumul harra wa saraabeela taqeekum baasakum; kazaalika yutimmu ni'matahoo alaikum la'allakum tuslimoon", english: "It is Allah Who made out of the things He created, some things to give you shade; of the hills He made some for your shelter; He made you garments to protect you from heat, and coats of mail to protect you from your (mutual) violence. Thus does He complete His favours on you, that ye may bow to His Will (in Islam)", romanUrdu: "Usne apni paida ki hui bahut si cheezon se tumhare liye saaye ka intezam kiya, pahadon mein tumhare liye panaah-gaahein (places of refuge) banayi, aur tumhein aisi poshakein (garments) bakshi jo tumhein garmi se bachati hain aur kuch dusri poshakein jo aapas ki jung mein tumhari hifazat karti hain, is tarah woh tumpar apni niyamaton ki takmeel karta hai shayad ke tum farmabardar bano" },
    { number: 82, arabic: "فَإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْكَ ٱلْبَلَٰغُ ٱلْمُبِينُ", transliteration: "Fain tawallaw fainnama AAalayka albalaghu almubeenu", transliterationB: "Fa in tawallaw fa innamaa 'alaikal balaaghul mubeen", english: "But if they turn away, thy duty is only to preach the clear Message", romanUrdu: "Ab agar yeh log mooh moadte hain to (aey Muhammad) , tumpar saaf saaf paighaam e haqq pahuncha dene ke siwa aur koi zimmedari nahin hai" },
    { number: 83, arabic: "يَعْرِفُونَ نِعْمَتَ ٱللَّهِ ثُمَّ يُنكِرُونَهَا وَأَكْثَرُهُمُ ٱلْكَٰفِرُونَ", transliteration: "YaAArifoona niAAmata Allahi thumma yunkiroonaha waaktharuhumu alkafiroona", transliterationB: "Ya'rifoona ni'matal laahi summa yunkiroonahaa wa aksaruhumul kaafiroon", english: "They recognise the favours of Allah; then they deny them; and most of them are (creatures) ungrateful", romanUrdu: "Yeh Allah ke ehsan ko pehchante hain, phir iska inkar karte hain aur in mein beshtar aisey hain jo haqq maanne ke liye tayyar nahin hain" },
    { number: 84, arabic: "وَيَوْمَ نَبْعَثُ مِن كُلِّ أُمَّةٍۢ شَهِيدًۭا ثُمَّ لَا يُؤْذَنُ لِلَّذِينَ كَفَرُوا۟ وَلَا هُمْ يُسْتَعْتَبُونَ", transliteration: "Wayawma nabAAathu min kulli ommatin shaheedan thumma la yuthanu lillatheena kafaroo wala hum yustaAAtaboona", transliterationB: "Wa yawma nab'asu min kulli ummatin shaheedan summa laa yu'zanu lillazeena kafaroo wa laa hum yusta'taboon", english: "One Day We shall raise from all Peoples a Witness: then will no excuse be accepted from Unbelievers, nor will they receive any favours", romanUrdu: "(Inhein kuch hosh bhi hai ke us roz kya banegi) jabke hum har ummat mein se ek gawaah khada karenge, phir kaafiron ko na hujjatein (excuses) pesh karne ka mauqa diya jayega na unse tawba o istagfar hi ka mutalba kiya jayega" },
    { number: 85, arabic: "وَإِذَا رَءَا ٱلَّذِينَ ظَلَمُوا۟ ٱلْعَذَابَ فَلَا يُخَفَّفُ عَنْهُمْ وَلَا هُمْ يُنظَرُونَ", transliteration: "Waitha raa allatheena thalamoo alAAathaba fala yukhaffafu AAanhum wala hum yuntharoona", transliterationB: "Wa izaa ra al lazeena zalamul 'azaaba falaa yukhaf fafu 'anhum wa laa hum yunzaroon", english: "When the wrong-doers (actually) see the Penalty, then will it in no way be mitigated, nor will they then receive respite", romanUrdu: "Zalim log jab ek dafa azaab dekh lenge to iske baad na unke azaab mein koi takhfif (lightened /halka) ki jayegi aur na unhein ek lamha bhar ki mohlat di jayegi" },
    { number: 86, arabic: "وَإِذَا رَءَا ٱلَّذِينَ أَشْرَكُوا۟ شُرَكَآءَهُمْ قَالُوا۟ رَبَّنَا هَٰٓؤُلَآءِ شُرَكَآؤُنَا ٱلَّذِينَ كُنَّا نَدْعُوا۟ مِن دُونِكَ ۖ فَأَلْقَوْا۟ إِلَيْهِمُ ٱلْقَوْلَ إِنَّكُمْ لَكَٰذِبُونَ", transliteration: "Waitha raa allatheena ashrakoo shurakaahum qaloo rabbana haolai shurakaona allatheena kunna nadAAoo min doonika faalqaw ilayhimu alqawla innakum lakathiboona", transliterationB: "Wa izaa ra al lazeena ashrakoo shurakaaa'ahum qaaloo Rabbana haaa'ulaaa'i shurakaaa'unal lazeena kunnaa nad'oo min doonika fa alqaw ilaihimul qawla innakum lakaaziboon", english: "When those who gave partners to Allah will see their \"partners\", they will say: \"Our Lord! these are our 'partners,' those whom we used to invoke besides Thee.\" But they will throw back their word at them (and say): \"Indeed ye are liars", romanUrdu: "Aur jab woh log jinhon ne duniya mein shirk kiya tha apne thehraye huey shareekon ko dekhenge to kahenge “ aey parwardigar, yahi hain hamare woh shareek jinhein hum tujhey chodh kar pukara karte thay” ispar unke woh mabood unhein saaf jawab denge ke “tum jhootey ho”" },
    { number: 87, arabic: "وَأَلْقَوْا۟ إِلَى ٱللَّهِ يَوْمَئِذٍ ٱلسَّلَمَ ۖ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ", transliteration: "Waalqaw ila Allahi yawmaithin alssalama wadalla AAanhum ma kanoo yaftaroona", transliterationB: "Wa alqaw ilal laahi yawma'izinis salama wa dalla 'anhum maa kaanoo yaftaroon", english: "That Day shall they (openly) show (their) submission to Allah; and all their inventions shall leave them in the lurch", romanUrdu: "Us waqt yeh sab Allah ke aagey jhuk jaayenge aur unki woh saari iftara-pardaziyan(forgery) rafu-chakkar (vanish) ho jayengi jo yeh duniya mein karte rahey thay" },
    { number: 88, arabic: "ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ زِدْنَٰهُمْ عَذَابًۭا فَوْقَ ٱلْعَذَابِ بِمَا كَانُوا۟ يُفْسِدُونَ", transliteration: "Allatheena kafaroo wasaddoo AAan sabeeli Allahi zidnahum AAathaban fawqa alAAathabi bima kanoo yufsidoona", transliterationB: "Allazeena kafaroo wa saddoo 'an sabeelil laahi zidnaahum 'azaaban fawqal 'azaabi bimaa kaanoo yufsidoon", english: "Those who reject Allah and hinder (men) from the Path of Allah - for them will We add Penalty to Penalty; for that they used to spread mischief", romanUrdu: "Jin logon ne khud kufr ki raah ikhtiyar ki aur dusron ko Allah ki raah se roka unhein hum azaab par azaab denge us fasaad ke badle jo woh duniya mein barpa karte rahey" },
    { number: 89, arabic: "وَيَوْمَ نَبْعَثُ فِى كُلِّ أُمَّةٍۢ شَهِيدًا عَلَيْهِم مِّنْ أَنفُسِهِمْ ۖ وَجِئْنَا بِكَ شَهِيدًا عَلَىٰ هَٰٓؤُلَآءِ ۚ وَنَزَّلْنَا عَلَيْكَ ٱلْكِتَٰبَ تِبْيَٰنًۭا لِّكُلِّ شَىْءٍۢ وَهُدًۭى وَرَحْمَةًۭ وَبُشْرَىٰ لِلْمُسْلِمِينَ", transliteration: "Wayawma nabAAathu fee kulli ommatin shaheedan AAalayhim min anfusihim wajina bika shaheedan AAala haolai wanazzalna AAalayka alkitaba tibyanan likulli shayin wahudan warahmatan wabushra lilmuslimeena", transliterationB: "Wa yawma nab'asu fee kulli ummmatin shaheedan 'alaihim min anfusihim wa ji'naa bika shaheedan 'alaa haaa'ulaaa'; wa nazzalnaa 'alaikal Kitaaba tibyaanal likulli shai'inw wa hudanw wa rahmatanw wa bushraa lilmuslimeen", english: "One day We shall raise from all Peoples a witness against them, from amongst themselves: and We shall bring thee as a witness against these (thy people): and We have sent down to thee the Book explaining all things, a Guide, a Mercy, and Glad Tidings to Muslims", romanUrdu: "(Aey Muhammad, inhein us din se khabardar kardo) jabke hum har ummat mein khud usi ke andar se ek gawaah utha khada karenge jo uske muqable mein shahadat (witness/gawahi) dega. Aur in logon ke muqable mein shahadat dene ke liye hum tumhein layenge aur (yeh usi shadat ki tayyari hai ke) humne yeh kitab tumpar nazil kardi hai jo har cheez ki saaf saaf wazahat karne wali hai aur hidayat o rehmat aur basharat hai un logon ke liye jinhon ne sar-e-tasleem kham kar diya hai" },
    { number: 90, arabic: "۞ إِنَّ ٱللَّهَ يَأْمُرُ بِٱلْعَدْلِ وَٱلْإِحْسَٰنِ وَإِيتَآئِ ذِى ٱلْقُرْبَىٰ وَيَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ وَٱلْبَغْىِ ۚ يَعِظُكُمْ لَعَلَّكُمْ تَذَكَّرُونَ", transliteration: "Inna Allaha yamuru bialAAadli waalihsani waeetai thee alqurba wayanha AAani alfahshai waalmunkari waalbaghyi yaAAithukum laAAallakum tathakkaroona", transliterationB: "Innal laaha yaamaru bil 'adli wal ihsaani wa eetaaa'i zil qurbaa wa yanhaa 'anil fahshaaa'i wal munkari walbagh-i' ya'izukum la'allakum tazakkkaroon", english: "Allah commands justice, the doing of good, and liberality to kith and kin, and He forbids all shameful deeds, and injustice and rebellion: He instructs you, that ye may receive admonition", romanUrdu: "Allah adal (justice) aur ehsaan (generosity) aur sila rehmi ka hukum deta hai aur badhi(wickedness) o behayai aur zulm o zyadati se mana karta hai. Woh tumhein naseehat karta hai taa-ke tum sabaq lo" },
    { number: 91, arabic: "وَأَوْفُوا۟ بِعَهْدِ ٱللَّهِ إِذَا عَٰهَدتُّمْ وَلَا تَنقُضُوا۟ ٱلْأَيْمَٰنَ بَعْدَ تَوْكِيدِهَا وَقَدْ جَعَلْتُمُ ٱللَّهَ عَلَيْكُمْ كَفِيلًا ۚ إِنَّ ٱللَّهَ يَعْلَمُ مَا تَفْعَلُونَ", transliteration: "Waawfoo biAAahdi Allahi itha AAahadtum wala tanqudoo alaymana baAAda tawkeediha waqad jaAAaltumu Allaha AAalaykum kafeelan inna Allaha yaAAlamu ma tafAAaloona", transliterationB: "Wa awfoo bi Ahdil laahi izaa 'aahattum wa laa tanqudul aimaana ba'da tawkeedihaa wa qad ja'altumul laaha 'alaikum kafeelaa; innal laaha ya'lamu maa taf'aloon", english: "Fulfil the Covenant of Allah when ye have entered into it, and break not your oaths after ye have confirmed them; indeed ye have made Allah your surety; for Allah knoweth all that ye do", romanUrdu: "Allah ke ahad (covenant) ko poora karo jabke tumne ussey koi ahad bandha ho, aur apni kasmein pukhta karne ke baad todh na daalo jabke tum Allah ko apne upar gawah bana chuke ho. Allah tumhare sab afaal se bakhabar hai" },
    { number: 92, arabic: "وَلَا تَكُونُوا۟ كَٱلَّتِى نَقَضَتْ غَزْلَهَا مِنۢ بَعْدِ قُوَّةٍ أَنكَٰثًۭا تَتَّخِذُونَ أَيْمَٰنَكُمْ دَخَلًۢا بَيْنَكُمْ أَن تَكُونَ أُمَّةٌ هِىَ أَرْبَىٰ مِنْ أُمَّةٍ ۚ إِنَّمَا يَبْلُوكُمُ ٱللَّهُ بِهِۦ ۚ وَلَيُبَيِّنَنَّ لَكُمْ يَوْمَ ٱلْقِيَٰمَةِ مَا كُنتُمْ فِيهِ تَخْتَلِفُونَ", transliteration: "Wala takoonoo kaallatee naqadat ghazlaha min baAAdi quwwatin ankathan tattakhithoona aymanakum dakhalan baynakum an takoona ommatun hiya arba min ommatin innama yablookumu Allahu bihi walayubayyinanna lakum yawma alqiyamati ma kuntum feehi takhtalifoona", transliterationB: "Wa laa takoonoo kallatee naqadat ghazlahaa mim ba'di quwwatin ankaasaa; tattakhizoona aimaanakum dakhlalam bainakum an takoona ummatun hiya arbaa min ummah; innnamaa yablookumul laahu bih; wa la yubaiyinanna lakum yawmal Qiyaamati maa kuntum fee takhtalifoon", english: "And be not like a woman who breaks into untwisted strands the yarn which she has spun, after it has become strong. Nor take your oaths to practise deception between yourselves, lest one party should be more numerous than another: for Allah will test you by this; and on the Day of Judgment He will certainly make clear to you (the truth of) that wherein ye disagree", romanUrdu: "Tumhari halat us aurat ki si na ho jaye jisne aap hi mehnat se soot kaata (spun yarn) aur phir aap hi usey tukde tukde kar dala. Tum apni kasamo ko aapas ke maamlaat mein makar o fareb ka hathiyar banate ho taa-ke ek qaum dusri qaum se badhkar faiyde hasil karey halaanke Allah is ahad o paimaan ke zariye se tumko aazmaish mein daalta hai. Aur zaroor woh qayamat ke roz tumhare tamaam ikhtilafaat ki haqeeqat tumpar khol dega" },
    { number: 93, arabic: "وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَلَٰكِن يُضِلُّ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۚ وَلَتُسْـَٔلُنَّ عَمَّا كُنتُمْ تَعْمَلُونَ", transliteration: "Walaw shaa Allahu lajaAAalakum ommatan wahidatan walakin yudillu man yashao wayahdee man yashao walatusalunna AAamma kuntum taAAmaloona", transliterationB: "Wa law shaaa'al laahu laja'alakum ummmatanw waahidatanw wa laakiny yudillu many-yashaaa'u wa yahdee many-yashaaa'; wa latus'alunna 'ammaa kuntum ta'maloon", english: "If Allah so willed, He could make you all one people: But He leaves straying whom He pleases, and He guides whom He pleases: but ye shall certainly be called to account for all your actions", romanUrdu: "Agar Allah ki mashiyat yeh hoti (ke tum mein koi ikhtilaf na ho) to woh tum sabko ek hi ummat bana deta, magar woh jisey chahta hai gumraahi mein daalta hai aur jisey chahta hain raah e raast dikha deta hai. Aur zaroor tumse tumhare aamaal ki baaz-purs hokar rahegi" },
    { number: 94, arabic: "وَلَا تَتَّخِذُوٓا۟ أَيْمَٰنَكُمْ دَخَلًۢا بَيْنَكُمْ فَتَزِلَّ قَدَمٌۢ بَعْدَ ثُبُوتِهَا وَتَذُوقُوا۟ ٱلسُّوٓءَ بِمَا صَدَدتُّمْ عَن سَبِيلِ ٱللَّهِ ۖ وَلَكُمْ عَذَابٌ عَظِيمٌۭ", transliteration: "Wala tattakhithoo aymanakum dakhalan baynakum fatazilla qadamun baAAda thubootiha watathooqoo alssooa bima sadadtum AAan sabeeli Allahi walakum AAathabun AAatheemun", transliterationB: "Wa laa tattakhizooo aimaanakum dakhalam bainakum ftazilla qadamum ba'da subootihaa wa tazooqus sooo'a bimmaa sadattum 'an sabeelil laahi wa lakum 'azaabun 'azeem", english: "And take not your oaths, to practise deception between yourselves, with the result that someone's foot may slip after it was firmly planted, and ye may have to taste the evil (consequences) of having hindered (men) from the Path of Allah, and a Mighty Wrath descend on you", romanUrdu: "(aur Aey Musalmaano) tum apni kasamon ko aapas mein ek dusre ko dhoka dene ka zariya na bana lena, kahin aisa na ho ke koi qadam jamne ke baad ukhad jaye aur tum is jurm ki padash mein ke tumne logon ko Allah ki raah se roka, bura nateeja dekho aur sakht saza bhugto" },
    { number: 95, arabic: "وَلَا تَشْتَرُوا۟ بِعَهْدِ ٱللَّهِ ثَمَنًۭا قَلِيلًا ۚ إِنَّمَا عِندَ ٱللَّهِ هُوَ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ", transliteration: "Wala tashtaroo biAAahdi Allahi thamanan qaleelan innama AAinda Allahi huwa khayrun lakum in kuntum taAAlamoona", transliterationB: "Wa laa tashtaroo bi 'ahdil laahi samanan qaleelaa; innamaa 'indal laahi huwa khairul lakum in kuntum ta'lamoon", english: "Nor sell the covenant of Allah for a miserable price: for with Allah is (a prize) far better for you, if ye only knew", romanUrdu: "Allah ke ahad ko thode se faiyde ke badle na bech daalo (sell off/barter away), jo kuch Allah ke paas hai woh tumhare liye zyada behtar hai agar tum jaano" },
    { number: 96, arabic: "مَا عِندَكُمْ يَنفَدُ ۖ وَمَا عِندَ ٱللَّهِ بَاقٍۢ ۗ وَلَنَجْزِيَنَّ ٱلَّذِينَ صَبَرُوٓا۟ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Ma AAindakum yanfadu wama AAinda Allahi baqin walanajziyanna allatheena sabaroo ajrahum biahsani ma kanoo yaAAmaloona", transliterationB: "maa 'indakum yanfadu wa maa 'indal laahi baaq; wa lanajziyannal lazeena sabarooo ajjrahum bi ahsani maa kaanoo ya'maloon", english: "What is with you must vanish: what is with Allah will endure. And We will certainly bestow, on those who patiently persevere, their reward according to the best of their actions", romanUrdu: "Jo kuch tumhare paas hai woh kharch ho janey wala hai aur jo kuch Allah ke paas hai wahi baaqi rehne wala hai, aur hum zaroor sabr se kaam lene walon ko unke ajar unke behtareen aamaal ke mutaabiq denge" },
    { number: 97, arabic: "مَنْ عَمِلَ صَٰلِحًۭا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌۭ فَلَنُحْيِيَنَّهُۥ حَيَوٰةًۭ طَيِّبَةًۭ ۖ وَلَنَجْزِيَنَّهُمْ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Man AAamila salihan min thakarin aw ontha wahuwa muminun falanuhyiyannahu hayatan tayyibatan walanajziyannahum ajrahum biahsani ma kanoo yaAAmaloona", transliterationB: "Man 'amila saaliham min zakarin aw unsaa wa huwa mu'minun falanuhyiyannahoo hayaatan taiiyibatanw wa lanajzi yannnahum ajrahum bi ahsani maa kaanoo ya'maloon", english: "Whoever works righteousness, man or woman, and has Faith, verily, to him will We give a new Life, a life that is good and pure and We will bestow on such their reward according to the best of their actions", romanUrdu: "Jo shaks bhi neik amal karega, khwa woh mard ho ya aurat, bashart ye ke ho woh momin, usey hum duniya mein pakeeza zindagi basar karayenge aur (aakhirat mein) aisey logon ko unke ajar unke behtareen aamaal ke mutabiq bakshenge" },
    { number: 98, arabic: "فَإِذَا قَرَأْتَ ٱلْقُرْءَانَ فَٱسْتَعِذْ بِٱللَّهِ مِنَ ٱلشَّيْطَٰنِ ٱلرَّجِيمِ", transliteration: "Faitha qarata alqurana faistaAAith biAllahi mina alshshaytani alrrajeemi", transliterationB: "Fa izaa qara tal Quraana fasta'iz billaahi minashh Shai taanir rajeem", english: "When thou dost read the Qur'an, seek Allah's protection from Satan the rejected one", romanUrdu: "Phir jab tum Quran padhne lago to Shaytan e rajeem (accursed) se khuda ki panaah maang liya karo" },
    { number: 99, arabic: "إِنَّهُۥ لَيْسَ لَهُۥ سُلْطَٰنٌ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", transliteration: "Innahu laysa lahu sultanun AAala allatheena amanoo waAAala rabbihim yatawakkaloona", transliterationB: "Innahoo laisa lahoo sultaanun 'alal lazeena aamanoo wa 'alaa Rabbihim yatawakkaloon", english: "No authority has he over those who believe and put their trust in their Lord", romanUrdu: "Usey un logon par tasallut (power/authority) hasil nahin hota jo iman latey aur apne Rubb par bharosa karte hain" },
    { number: 100, arabic: "إِنَّمَا سُلْطَٰنُهُۥ عَلَى ٱلَّذِينَ يَتَوَلَّوْنَهُۥ وَٱلَّذِينَ هُم بِهِۦ مُشْرِكُونَ", transliteration: "Innama sultanuhu AAala allatheena yatawallawnahu waallatheena hum bihi mushrikoona", transliterationB: "Innnamaa sultaanuhoo 'alal lazeena yatawallawnahoo wallazeena hum bihee mushrikoon", english: "His authority is over those only, who take him as patron and who join partners with Allah", romanUrdu: "Uska zoar to unhi logon par chalta hai jo usko apna sarparast banate aur uske behkane se shirk karte hain" },
    { number: 101, arabic: "وَإِذَا بَدَّلْنَآ ءَايَةًۭ مَّكَانَ ءَايَةٍۢ ۙ وَٱللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ قَالُوٓا۟ إِنَّمَآ أَنتَ مُفْتَرٍۭ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ", transliteration: "Waitha baddalna ayatan makana ayatin waAllahu aAAlamu bima yunazzilu qaloo innama anta muftarin bal aktharuhum la yaAAlamoona", transliterationB: "Wa izaa baddalnaaa Aayatam makaana Aayatinw wal laahu a'lamu bimaa yunazzilu qaalooo innamaa anta muftar; bal aksaruhum laa ya'lamoon", english: "When We substitute one revelation for another,- and Allah knows best what He reveals (in stages),- they say, \"Thou art but a forger\": but most of them understand not", romanUrdu: "Jab hum ek ayat ki jagah dusri aayat nazil karte hain Allah behtar jaanta hia ke woh kya nazil karey to yeh log kehte hain ke tum yeh Quran khud ghadte ho. Asal baat yeh hai ke in mein se aksar log haqeeqat se na-waqif hain" },
    { number: 102, arabic: "قُلْ نَزَّلَهُۥ رُوحُ ٱلْقُدُسِ مِن رَّبِّكَ بِٱلْحَقِّ لِيُثَبِّتَ ٱلَّذِينَ ءَامَنُوا۟ وَهُدًۭى وَبُشْرَىٰ لِلْمُسْلِمِينَ", transliteration: "Qul nazzalahu roohu alqudusi min rabbika bialhaqqi liyuthabbita allatheena amanoo wahudan wabushra lilmuslimeena", transliterationB: "Qul nazzalahoo Roohul Qudusi mir Rabbika bilhaqqi liyusabbital lazeena aamanoo wa hudanw wa bushraa lilmuslimeen", english: "Say, the Holy Spirit has brought the revelation from thy Lord in Truth, in order to strengthen those who believe, and as a Guide and Glad Tidings to Muslims", romanUrdu: "Insey kaho ke isey to rooh-ul-quddus ne theek theek mere Rubb ki taraf se ba-tadreej nazil kiya hai taa-ke iman laney walon ke iman ko pukhta karey aur farma-bardaron ko zindagi ke maamlaat mein seedhi raah bataye aur unhein falaah o saadat ki khush khabri de" },
    { number: 103, arabic: "وَلَقَدْ نَعْلَمُ أَنَّهُمْ يَقُولُونَ إِنَّمَا يُعَلِّمُهُۥ بَشَرٌۭ ۗ لِّسَانُ ٱلَّذِى يُلْحِدُونَ إِلَيْهِ أَعْجَمِىٌّۭ وَهَٰذَا لِسَانٌ عَرَبِىٌّۭ مُّبِينٌ", transliteration: "Walaqad naAAlamu annahum yaqooloona innama yuAAallimuhu basharun lisanu allathee yulhidoona ilayhi aAAjamiyyun wahatha lisanun AAarabiyyun mubeenun", transliterationB: "Wa laqad na'lamu annahum yaqooloona innamaa yu'allimuhoo bashar; lisaanul lazee yulhidoona ilaihi a'ja miyyunw wa haaza lisaanun 'Arabiyyum mubeen", english: "We know indeed that they say, \"It is a man that teaches him.\" The tongue of him they wickedly point to is notably foreign, while this is Arabic, pure and clear", romanUrdu: "Humein maloom hai yeh log tumhare mutaaliq kehte hain ke is shaks ko ek aadmi sikhata padhata hai. Halaanke unka ishara jis aadmi ki taraf hai uski zubaan ajami hai aur yeh saaf arabi zubaan hai" },
    { number: 104, arabic: "إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِـَٔايَٰتِ ٱللَّهِ لَا يَهْدِيهِمُ ٱللَّهُ وَلَهُمْ عَذَابٌ أَلِيمٌ", transliteration: "Inna allatheena la yuminoona biayati Allahi la yahdeehimu Allahu walahum AAathabun aleemun", transliterationB: "Innal lazeena laa yu'minoona bi Aayaatil laahi laa yahdehimul laahu wa lahum 'azaabun aleem", english: "Those who believe not in the Signs of Allah,- Allah will not guide them, and theirs will be a grievous Penalty", romanUrdu: "Haqeeqat yeh hai ke jo log Allah ki aayat ko nahin maante Allah kabhi unko saheeh baat tak pahunchne ki taufeeq nahin deta aur aise logon ke liye dardnaak azaab hai" },
    { number: 105, arabic: "إِنَّمَا يَفْتَرِى ٱلْكَذِبَ ٱلَّذِينَ لَا يُؤْمِنُونَ بِـَٔايَٰتِ ٱللَّهِ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْكَٰذِبُونَ", transliteration: "Innama yaftaree alkathiba allatheena la yuminoona biayati Allahi waolaika humu alkathiboona", transliterationB: "Innamaa yaftaril kazibal lazeena laa yu'minoona bi Aayaatil laahi wa ulaaa'ika humul kaaziboon", english: "It is those who believe not in the Signs of Allah, that forge falsehood: it is they who lie", romanUrdu: "(Jhooti baatein Nabi nahin ghadta balke) jhoot woh log ghad rahey hain jo Allah ki aayat ko nahin maante, wahi haqeeqat mein jhootey hain" },
    { number: 106, arabic: "مَن كَفَرَ بِٱللَّهِ مِنۢ بَعْدِ إِيمَٰنِهِۦٓ إِلَّا مَنْ أُكْرِهَ وَقَلْبُهُۥ مُطْمَئِنٌّۢ بِٱلْإِيمَٰنِ وَلَٰكِن مَّن شَرَحَ بِٱلْكُفْرِ صَدْرًۭا فَعَلَيْهِمْ غَضَبٌۭ مِّنَ ٱللَّهِ وَلَهُمْ عَذَابٌ عَظِيمٌۭ", transliteration: "Man kafara biAllahi min baAAdi eemanihi illa man okriha waqalbuhu mutmainnun bialeemani walakin man sharaha bialkufri sadran faAAalayhim ghadabun mina Allahi walahum AAathabun AAatheemun", transliterationB: "man kafara billaahi mim ba'di eemaanihee illaa man ukriha wa qalbuhoo mutmma'innum bil eemaani wa laakim man sharaha bilkufri sadran fa'alaihim ghadabum minal laahi wa lahum 'azaabun 'azeem", english: "Any one who, after accepting faith in Allah, utters Unbelief,- except under compulsion, his heart remaining firm in Faith - but such as open their breast to Unbelief, on them is Wrath from Allah, and theirs will be a dreadful Penalty", romanUrdu: "Jo shaks iman laney ke baad kufr karey (woh agar) majboor kiya gaya ho aur dil uska iman par mutmaeen (convinced) ho (tab to khair) magar jisne dil ki raza-mandi se kufr ko qabool karliya uspar Allah ka gazab hai aur aisey sab logon ke liye bada azaab hai" },
    { number: 107, arabic: "ذَٰلِكَ بِأَنَّهُمُ ٱسْتَحَبُّوا۟ ٱلْحَيَوٰةَ ٱلدُّنْيَا عَلَى ٱلْءَاخِرَةِ وَأَنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَٰفِرِينَ", transliteration: "Thalika biannahumu istahabboo alhayata alddunya AAala alakhirati waanna Allaha la yahdee alqawma alkafireena", transliterationB: "Zaalika bi annahumus tahabbul hayaatad dunyaa 'alal Aakhirati wa annal laaha laa yahdil qawmal kaafireen", english: "This because they love the life of this world better than the Hereafter: and Allah will not guide those who reject Faith", romanUrdu: "Yeh isliye ke unhon ne aakhirat ke muqable mein duniya ki zindagi ko pasand karliya, aur Allah ka qaida hai ke woh un logon ko raah e nijaat nahin dikhata jo uski niyamat ka kufraan karein" },
    { number: 108, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ طَبَعَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ وَسَمْعِهِمْ وَأَبْصَٰرِهِمْ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْغَٰفِلُونَ", transliteration: "Olaika allatheena tabaAAa Allahu AAala quloobihim wasamAAihim waabsarihim waolaika humu alghafiloona", transliterationB: "Ulaaa'ikal lazeena taba'al laahu 'alaa quloobihim wa sam'ihim wa absaarihim wa ulaaa'ika humul ghaafiloon", english: "Those are they whose hearts, ears, and eyes Allah has sealed up, and they take no heed", romanUrdu: "Yeh woh log hain jinke dilon aur kaano aur aankhon par Allah ne mohar (seal) laga di hai yeh gaflat mein doob chuke hain" },
    { number: 109, arabic: "لَا جَرَمَ أَنَّهُمْ فِى ٱلْءَاخِرَةِ هُمُ ٱلْخَٰسِرُونَ", transliteration: "La jarama annahum fee alakhirati humu alkhasiroona", transliterationB: "Laa jarama annnahum fil Aakhirati humul khassiroon", english: "Without doubt, in the Hereafter they will perish", romanUrdu: "Zaroor hai ke aakhirat mein yahi khasare mein rahein" },
    { number: 110, arabic: "ثُمَّ إِنَّ رَبَّكَ لِلَّذِينَ هَاجَرُوا۟ مِنۢ بَعْدِ مَا فُتِنُوا۟ ثُمَّ جَٰهَدُوا۟ وَصَبَرُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌۭ رَّحِيمٌۭ", transliteration: "Thumma inna rabbaka lillatheena hajaroo min baAAdi ma futinoo thumma jahadoo wasabaroo inna rabbaka min baAAdiha laghafoorun raheemun", transliterationB: "Summa inna Rabbaka lillazeena haajaroo mim ba'dimaa futinoo summma jaahadoo wa sabaroo inna Rabbaka mim ba'dihaa la Ghafoorur Raheem", english: "But verily thy Lord,- to those who leave their homes after trials and persecutions,- and who thereafter strive and fight for the faith and patiently persevere,- Thy Lord, after all this is oft-forgiving, Most Merciful", romanUrdu: "Ba-khilaf iske jin logon ka haal yeh hai ke jab (iman laney ki wajah se) woh sataye gaye to unhon ne ghar-baar chodh diye, hijrat ki, raah e khuda mein sakhtiyan jheli aur sabr se kaam liya, unke liye yaqeenan tera Rubb gafoor o raheem hai" },
    { number: 111, arabic: "۞ يَوْمَ تَأْتِى كُلُّ نَفْسٍۢ تُجَٰدِلُ عَن نَّفْسِهَا وَتُوَفَّىٰ كُلُّ نَفْسٍۢ مَّا عَمِلَتْ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Yawma tatee kullu nafsin tujadilu AAan nafsiha watuwaffa kullu nafsin ma AAamilat wahum la yuthlamoona", transliterationB: "Yawma taatee kullu nafsin tujaadilu 'an nafsihaa wa tuwaffaa kullu nafsim maa 'amilat wa hum laa yuzlamoon", english: "One Day every soul will come up struggling for itself, and every soul will be recompensed (fully) for all its actions, and none will be unjustly dealt with", romanUrdu: "(In sab ka faisla us din hoga) jabke har mutanaffis apne hi bachao ki fikr mein laga hua hoga aur har ek ko uske kiye ka badla poora poora diya jayega aur kisi par zarra barabar zulm na hone payega" },
    { number: 112, arabic: "وَضَرَبَ ٱللَّهُ مَثَلًۭا قَرْيَةًۭ كَانَتْ ءَامِنَةًۭ مُّطْمَئِنَّةًۭ يَأْتِيهَا رِزْقُهَا رَغَدًۭا مِّن كُلِّ مَكَانٍۢ فَكَفَرَتْ بِأَنْعُمِ ٱللَّهِ فَأَذَٰقَهَا ٱللَّهُ لِبَاسَ ٱلْجُوعِ وَٱلْخَوْفِ بِمَا كَانُوا۟ يَصْنَعُونَ", transliteration: "Wadaraba Allahu mathalan qaryatan kanat aminatan mutmainnatan yateeha rizquha raghadan min kulli makanin fakafarat bianAAumi Allahi faathaqaha Allahu libasa aljooAAi waalkhawfi bima kanoo yasnaAAoona", transliterationB: "Wa darabal laahu masalan qaryatan kaanat aaminatam mutma'innatany yaaateehaa rizquhaa rghadam min kulli makaanin fakafarat bi an'umil laahi fa azaaqahal laahu libaasal joo'i walkhawfi bimaa kaanoo yasna'oon", english: "Allah sets forth a Parable: a city enjoying security and quiet, abundantly supplied with sustenance from every place: Yet was it ungrateful for the favours of Allah: so Allah made it taste of hunger and terror (in extremes) (closing in on it) like a garment (from every side), because of the (evil) which (its people) wrought", romanUrdu: "Allah ek basti ki misal deta hai , woh aman o itminaan ki zindagi basar kar rahi thi aur har taraf se usko ba-faragat rizq pahunch raha tha ke usne Allah ki niyamaton ka kufraan shuru kardiya , tab Allah ne uske bashindon ko unke kartooton ka yeh maza chakkhaya ke bhook aur khauf ki museebatein unpar chaa gayi" },
    { number: 113, arabic: "وَلَقَدْ جَآءَهُمْ رَسُولٌۭ مِّنْهُمْ فَكَذَّبُوهُ فَأَخَذَهُمُ ٱلْعَذَابُ وَهُمْ ظَٰلِمُونَ", transliteration: "Walaqad jaahum rasoolun minhum fakaththaboohu faakhathahumu alAAathabu wahum thalimoona", transliterationB: "Wa laqad jaaa'ahum Rasoolum minhum fakazzaboohu fa akhazahumul 'azaabu wa hum zaalimoon", english: "And there came to them a Messenger from among themselves, but they falsely rejected him; so the Wrath seized them even in the midst of their iniquities", romanUrdu: "Unke paas unki apni qaum mein se ek Rasool aaya magar unhon ne usko jhutla diya, aakhir e kaar azaab ne unko aa liya jabke woh zalim ho chuke thay" },
    { number: 114, arabic: "فَكُلُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ حَلَٰلًۭا طَيِّبًۭا وَٱشْكُرُوا۟ نِعْمَتَ ٱللَّهِ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ", transliteration: "Fakuloo mimma razaqakumu Allahu halalan tayyiban waoshkuroo niAAmata Allahi in kuntum iyyahu taAAbudoona", transliterationB: "Fakuloo mimmaa razaqa kumul laahu halaalan taiyibanw washkuroo ni'matal laahi in kuntum iyyaahu ta'budoon", english: "So eat of the sustenance which Allah has provided for you, lawful and good; and be grateful for the favours of Allah, if it is He Whom ye serve", romanUrdu: "Pas aey logon, Allah ne jo kuch halal aur paak rizq tumko bakhsa hai usey khao aur Allah ke ehsaan ka shukar ada karo agar tum waqayi usi ki bandagi karne waley ho" },
    { number: 115, arabic: "إِنَّمَا حَرَّمَ عَلَيْكُمُ ٱلْمَيْتَةَ وَٱلدَّمَ وَلَحْمَ ٱلْخِنزِيرِ وَمَآ أُهِلَّ لِغَيْرِ ٱللَّهِ بِهِۦ ۖ فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍۢ وَلَا عَادٍۢ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Innama harrama AAalaykumu almaytata waalddama walahma alkhinzeeri wama ohilla lighayri Allahi bihi famani idturra ghayra baghin wala AAadin fainna Allaha ghafoorun raheemun", transliterationB: "Innamaa harrma 'alai kumul maitata waddama wa lahmal khinzeeri wa maaa uhilla lighairil laahi bihee famanid turra ghaira baaghinw wa laa 'aadin fa innal laaha Ghafoorur Raheem", english: "He has only forbidden you dead meat, and blood, and the flesh of swine, and any (food) over which the name of other than Allah has been invoked. But if one is forced by necessity, without wilful disobedience, nor transgressing due limits,- then Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Allah ne jo kuch tumpar haram kiya hai woh hai murdaar aur khoon aur suwar (khinzir/swine) ka gosht aur woh jaanwar jispar Allah ke siwa kisi aur ka naam liya gaya ho. Albatta bhook se majboor hokar agar koi in cheezon ko kha ley, bagair iske ke woh kanoon e ilahi ki khilaf warzi ka khwahish-mand ho, ya hadd e zaroorat se tajawuz ka murtakib ho, to yaqeenan Allah maaf karne aur reham farmane wala hai" },
    { number: 116, arabic: "وَلَا تَقُولُوا۟ لِمَا تَصِفُ أَلْسِنَتُكُمُ ٱلْكَذِبَ هَٰذَا حَلَٰلٌۭ وَهَٰذَا حَرَامٌۭ لِّتَفْتَرُوا۟ عَلَى ٱللَّهِ ٱلْكَذِبَ ۚ إِنَّ ٱلَّذِينَ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ لَا يُفْلِحُونَ", transliteration: "Wala taqooloo lima tasifu alsinatukumu alkathiba hatha halalun wahatha haramun litaftaroo AAala Allahi alkathiba inna allatheena yaftaroona AAala Allahi alkathiba la yuflihoona", transliterationB: "Wa laa taqooloo limaa tasifu alsinatukumul kaziba haaza halaalunw wa haazaa haraamul litaftaroo 'alal laahil kazib; innal lazeena yaftaroona 'alal laahil kaziba laa yuflihoon", english: "But say not - for any false thing that your tongues may put forth,- \"This is lawful, and this is forbidden,\" so as to ascribe false things to Allah. For those who ascribe false things to Allah, will never prosper", romanUrdu: "Aur yeh jo tumhari zubaanein jhoote ehkaam lagaya karti hain ke yeh cheez halal hai aur woh haram, to is tarah ke hukum laga kar Allah par jhoot na baandha karo, jo log Allah par jhoote iftara bandhte (ascribe lies) hain woh hargiz falaah nahin paya karte" },
    { number: 117, arabic: "مَتَٰعٌۭ قَلِيلٌۭ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "MataAAun qaleelun walahum AAathabun aleemun", transliterationB: "Mata'un qaleelunw wa lahum 'azaabun aleem", english: "(In such falsehood) is but a paltry profit; but they will have a most grievous Penalty", romanUrdu: "Duniya ka aish chandh roza hai aakhir e kaar unke liye dardnaak saza hai" },
    { number: 118, arabic: "وَعَلَى ٱلَّذِينَ هَادُوا۟ حَرَّمْنَا مَا قَصَصْنَا عَلَيْكَ مِن قَبْلُ ۖ وَمَا ظَلَمْنَٰهُمْ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "WaAAala allatheena hadoo harramna ma qasasna AAalayka min qablu wama thalamnahum walakin kanoo anfusahum yathlimoona", transliterationB: "Wa 'alal lazeena haadoo harramnaa ma qasasnaa 'alaika min qablu wa maa zalamanaahum wa laakin kaanoo anfusahum wa laakin kaanoo anfusahum yazlimoon", english: "To the Jews We prohibited such things as We have mentioned to thee before: We did them no wrong, but they were used to doing wrong to themselves", romanUrdu: "Woh cheezein humne khaas taur par yahudiyon (jews) ke liye haram ki thi jinka zikr hum issey pehle tumse kar chuke hain aur yeh unpar hamara zulm na tha balke unka apna hi zulm tha jo woh apne upar kar rahey thay" },
    { number: 119, arabic: "ثُمَّ إِنَّ رَبَّكَ لِلَّذِينَ عَمِلُوا۟ ٱلسُّوٓءَ بِجَهَٰلَةٍۢ ثُمَّ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌۭ رَّحِيمٌ", transliteration: "Thumma inna rabbaka lillatheena AAamiloo alssooa bijahalatin thumma taboo min baAAdi thalika waaslahoo inna rabbaka min baAAdiha laghafoorun raheemun", transliterationB: "Summma inna Rabbaka lillazeena 'amilus sooo'a bijahaalatin summa taaboo mim ba'di zaaalika wa aslahoo inna Rabbaka mim ba'dihaa la Ghafoorur Raheem", english: "But verily thy Lord,- to those who do wrong in ignorance, but who thereafter repent and make amends,- thy Lord, after all this, is Oft-Forgiving, Most Merciful", romanUrdu: "Albatta jin logon ne jahalat ki bina par bura amal kiya aur phir tawba karke apne amal ki islah karli to yaqeenan tawba o islaah ke baad tera Rubb unke liye gafoor aur raheem hai" },
    { number: 120, arabic: "إِنَّ إِبْرَٰهِيمَ كَانَ أُمَّةًۭ قَانِتًۭا لِّلَّهِ حَنِيفًۭا وَلَمْ يَكُ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Inna ibraheema kana ommatan qanitan lillahi haneefan walam yaku mina almushrikeena", transliterationB: "Inna Ibraaheema kaana ummatan qaanital lillaahi Haneefanw wa lam yakuminal mushrikeen", english: "Abraham was indeed a model, devoutly obedient to Allah, (and) true in Faith, and he joined not gods with Allah", romanUrdu: "Waqiya yeh hai ke Ibrahim apni zaat se ek puri ummat tha, Allah ka muti e farman aur yaksu. Woh kabhi mushrik na tha" },
    { number: 121, arabic: "شَاكِرًۭا لِّأَنْعُمِهِ ۚ ٱجْتَبَىٰهُ وَهَدَىٰهُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Shakiran lianAAumihi ijtabahu wahadahu ila siratin mustaqeemin", transliterationB: "Shaakiral li an'umih; ijtabaahu wa hadaahu ilaa Siraatim Muustaqeem", english: "He showed his gratitude for the favours of Allah, who chose him, and guided him to a Straight Way", romanUrdu: "Allah ki niyamaton ka shukar ada karne wala tha. Allah ne usko muntakhab (chose) karliya aur seedha raasta dikhaya" },
    { number: 122, arabic: "وَءَاتَيْنَٰهُ فِى ٱلدُّنْيَا حَسَنَةًۭ ۖ وَإِنَّهُۥ فِى ٱلْءَاخِرَةِ لَمِنَ ٱلصَّٰلِحِينَ", transliteration: "Waataynahu fee alddunya hasanatan wainnahu fee alakhirati lamina alssaliheena", transliterationB: "Wa aatainaahu fid dunyaa hasanah; wa innahoo fil Aakhirati laminas saaliheen", english: "And We gave him Good in this world, and he will be, in the Hereafter, in the ranks of the Righteous", romanUrdu: "Duniya mein usko bhalayi di aur aakhirat mein woh yaqeenan saliheen mein se hoga" },
    { number: 123, arabic: "ثُمَّ أَوْحَيْنَآ إِلَيْكَ أَنِ ٱتَّبِعْ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًۭا ۖ وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Thumma awhayna ilayka ani ittabiAA millata ibraheema haneefan wama kana mina almushrikeena", transliterationB: "Summma awhainaa ilaika anit tabi' Millata Ibraaheema haneefaa; wa maa kaana minal mushrikeen", english: "So We have taught thee the inspired (Message), \"Follow the ways of Abraham the True in Faith, and he joined not gods with Allah", romanUrdu: "Phir humne tumhari taraf yeh wahee bheji ke yaksu hokar Ibrahim ke tareeqe par chalo aur woh mushrikon mein se na tha" },
    { number: 124, arabic: "إِنَّمَا جُعِلَ ٱلسَّبْتُ عَلَى ٱلَّذِينَ ٱخْتَلَفُوا۟ فِيهِ ۚ وَإِنَّ رَبَّكَ لَيَحْكُمُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ", transliteration: "Innama juAAila alssabtu AAala allatheena ikhtalafoo feehi wainna rabbaka layahkumu baynahum yawma alqiyamati feema kanoo feehi yakhtalifoona", transliterationB: "Innnamaa ju'ilas Sabtu 'alal lazeenakhtalafoo feeh; wa inna Rabbaka la yahkumu bainahum Yawmal Qiyaamati feemaa kaanoo feehi yakhtalifoon", english: "The Sabbath was only made (strict) for those who disagreed (as to its observance); But Allah will judge between them on the Day of Judgment, as to their differences", romanUrdu: "Raha sabt (Sabbath/ hafte ka din) to woh humne un logon par musallat kiya tha jinhon ne uske ehkaam mein ikhtilaf kiya, aur yaqeenan tera Rubb qayamat ke roz un sab baaton ka faisla kardega jin mein woh ikhtilaf karte rahey hain" },
    { number: 125, arabic: "ٱدْعُ إِلَىٰ سَبِيلِ رَبِّكَ بِٱلْحِكْمَةِ وَٱلْمَوْعِظَةِ ٱلْحَسَنَةِ ۖ وَجَٰدِلْهُم بِٱلَّتِى هِىَ أَحْسَنُ ۚ إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ ۖ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ", transliteration: "OdAAu ila sabeeli rabbika bialhikmati waalmawAAithati alhasanati wajadilhum biallatee hiya ahsanu inna rabbaka huwa aAAlamu biman dalla AAan sabeelihi wahuwa aAAlamu bialmuhtadeena", transliterationB: "Ud'u ilaa sabeeli Rabbika bilhikmati walmaw 'izatil hasanati wa jaadilhum billatee hiya ahsan; inna Rabbaka huwa a'almu biman dalla 'an sabeelihee wa Huwa a'lamu bilmuhtadeen", english: "Invite (all) to the Way of thy Lord with wisdom and beautiful preaching; and argue with them in ways that are best and most gracious: for thy Lord knoweth best, who have strayed from His Path, and who receive guidance", romanUrdu: "(Aey Nabi), apne Rubb ke raaste ki taraf dawat do hikmat aur umdah naseehat ke saath, aur logon se mubahisa(discuss) karo aise tareeqe par jo behtareen ho. Tumhara Rubb hi zyada behtar jaanta hai ke kaun uski raah se bhatka hua hai aur kaun raah-e-raast par hai" },
    { number: 126, arabic: "وَإِنْ عَاقَبْتُمْ فَعَاقِبُوا۟ بِمِثْلِ مَا عُوقِبْتُم بِهِۦ ۖ وَلَئِن صَبَرْتُمْ لَهُوَ خَيْرٌۭ لِّلصَّٰبِرِينَ", transliteration: "Wain AAaqabtum faAAaqiboo bimithli ma AAooqibtum bihi walain sabartum lahuwa khayrun lilssabireena", transliterationB: "Wa in 'aaqabtum fa'aaqiboo bimisli maa 'ooqibtum bihee wa la'in sabartum lahuwa khairul lissaabireen", english: "And if ye do catch them out, catch them out no worse than they catch you out: But if ye show patience, that is indeed the best (course) for those who are patient", romanUrdu: "Aur agar tum log badla lo to bas usi qadar le lo jis qadar tumpar zyadati ki gayi ho, lekin agar tum sabr karo to yaqeenan yeh sabr karne walon hi ke haqq mein behtar hai" },
    { number: 127, arabic: "وَٱصْبِرْ وَمَا صَبْرُكَ إِلَّا بِٱللَّهِ ۚ وَلَا تَحْزَنْ عَلَيْهِمْ وَلَا تَكُ فِى ضَيْقٍۢ مِّمَّا يَمْكُرُونَ", transliteration: "Waisbir wama sabruka illa biAllahi wala tahzan AAalayhim wala taku fee dayqin mimma yamkuroona", transliterationB: "Wasbir wa maa sabruka illaa billaah; wa laa tahzan 'alaihim wa laa taku fee daiqim mimmaa yamkuroon", english: "And do thou be patient, for thy patience is but from Allah; nor grieve over them: and distress not thyself because of their plots", romanUrdu: "(Aey Muhammad) sabr se kaam kiye jao aur tumhara yeh sabr Allah hi ki toufeeq se hai, in logon ki harakat par ranjh na karo aur na inki chaalbaaziyon par dil tangg (distress) ho" },
    { number: 128, arabic: "إِنَّ ٱللَّهَ مَعَ ٱلَّذِينَ ٱتَّقَوا۟ وَّٱلَّذِينَ هُم مُّحْسِنُونَ", transliteration: "Inna Allaha maAAa allatheena ittaqaw waallatheena hum muhsinoona", transliterationB: "Innal laaha ma'al lazeenat taqaw wal lazeena hum muhsinoon", english: "For Allah is with those who restrain themselves, and those who do good", romanUrdu: "Allah un logon ke saath hai jo taqwa se kaam letay hain aur ehsan par amal karte hain" }
  ]
};
